export interface PageContent { image: string; paragraphs: BilingualText[]; }

export const municipalityOverview: PageContent = { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-paroysiasi.jpg', paragraphs: [{ el: 'Σημαντικότερες φυσικές ομορφιές που μπορεί ο επισκέπτης να συναντήσει στο ταξίδι της γνωριμίας του με τη Λευκάδα είναι:', en: 'The most important natural beauties that the visitor may encounter on his journey of getting to know Lefkada are:' }, { el: 'Η Γύρα: στενή λωρίδα λευκής αμμουδιάς μήκους 7 χλμ., που αγκαλιάζει τη λιμνοθάλασσα στο βόρειο σημείο του νησιού, κάνοντας το τοπίο μοναδικό. Ξεκινά πίσω σχεδόν από το κάστρο της Αγίας Μαύρας δημιουργώντας την Αμμόγλωσσα και φτάνει έως την άλλη άκρη, πέρα από την πόλη.', en: 'The Vulture: a narrow strip of white sandy beach 7 km long, hugging the lagoon in the northern part of the island, making the landscape unique. It starts almost behind the castle of Agia Mavra, creating Ammoglossa, and reaches the other end, beyond the town.' }, { el: 'Η Λιμνοθάλασσα στην πόλη της Λευκάδας και η Λιμνοθάλασσα των Στενών αποτελούν τοπία ιδιαίτερου φυσικού κάλλους. Έχουν ενταχθεί στο δίκτυο ΝΑTURA 2000 ως προστατευόμενες περιοχές με ιδιαίτερη οικολογική σημασία. Η περιοχή της Λιμνοθάλασσας στην πόλη της Λευκάδας παρουσιάζει επίσης ενδιαφέρον ως μεταναστευτικός σταθμός πουλιών, χαρακτηρισμένος από τη συνθήκη RAMSAR ως υδροβιότοπος διεθνούς σημασίας. Εκεί συναντά κανείς πολλά και σπάνια είδη πουλιών όπως κύκνους ερωδιούς, καλημάνες, διάφορα είδη γλάρων, παπιών και χηνών. Μέσα στη λιμνοθάλασσα υπάρχει το ιβάρι, ιχθυοκαλλιέργειες με ειδικές, παραδοσιακές καλαμωτές, όπου τα ψάρια ζουν και μεγαλώνουν σε φυσικές συνθήκες.', en: 'The Lagoon in the town of Lefkada and the Lagoon of the Straits are landscapes of outstanding natural beauty. They are included in the NATURA 2000 network as protected areas of particular ecological importance. The area of the Lagoon Lagoon in the town of Lefkada is also of interest as a bird migration station, classified by the RAMSAR Convention as a wetland of international importance. Many rare species of birds can be found there, such as heron swans, egrets, caiman, various species of gulls, ducks and geese. Inside the lagoon there is the Ivory Coast, fish farms with special, traditional reeds, where fish live and grow in natural conditions.' }, { el: 'O ελαιώνας: Στα βόρεια της πόλης της Λευκάδας απλώνεται ο ελαιώνας, με υπεραιωνόβιες ελιές. Όταν πρωτοήρθαν οι Τούρκοι στο νησί υπήρχαν ήδη γύρω στα 8500 ελαιόδεντρα, τόσο στον κάμπο της Λευκάδας, όσο και στα χωριά Απόλπαινα, Φρύνι και Άγιο Νικήτα. Οι Ενετοί που επέστρεψαν το 1684 έκαναν υποχρεωτική τη φύτευση ελαιοδέντρων. Έτσι οι Ενετοί θέλησαν να αντισταθμίσουν τη ζημιά που προκάλεσαν στους κατοίκους καταστρέφοντας τη ναυτιλία και το εμπόριο, μεταφέροντας την πόλη μακριά από το κάστρο κι επιβάλλοντας βαριά φορολογία. Κι ακόμα, αντικαθιστώντας τα σιτηρά, που μέχρι τότε σπέρνονταν στον κάμπο με τις ελιές, κρατούσαν τους κατοίκους σε μειονεκτική θέση για να τους ελέγχουν προμηθεύοντας τους οι ίδιοι το σιτάρι.', en: 'O ελαιώνας: To the north of the town of Lefkada lies the olive grove, with old olive trees. When the Turks first came to the island there were already around 8500 olive trees, both in the plain of Lefkada and in the villages of Apolpena, Frini and Agios Nikitas. The Venetians who returned in 1684 made the planting of olive trees compulsory. Thus the Venetians wanted to compensate for the damage they caused to the inhabitants by destroying shipping and trade, moving the town away from the castle and imposing heavy taxation. And further, by replacing the grain, which until then had been sown in the plain with olives, they kept the inhabitants at a disadvantage so that they could control them by supplying the grain themselves.' }, { el: 'Τα Πευκούλια: Μετά το χωριό Τσουκαλάδες και στο δρόμο προς τον Άγιο Νικήτα οι ελιές αντικαθίστανται από ένα δάσος με πεύκα. Είναι τα λεγόμενα Πευκούλια που καλύπτουν όλη την περιοχή αυτή και φτάνουν έως τη θάλασσα, καταλήγοντας σε μια μεγάλη αμμώδη που ονομάζεται κι αυτή Πευκούλια.', en: 'The Pefkoulia: After the village of Tsoukalades and on the road to Agios Nikitas the olive trees are replaced by a forest of pine trees. These are the so-called Pefkoulia that cover this entire area and reach the sea, ending in a large sandy area also called Pefkoulia.' }, { el: 'Οι Αλυκές: Από την άλλη πλευρά, προς τα ανατολικά, εξώ από την πόλη της Λευκάδας υπάρχουν οι αλυκές της πόλης. Έχουν πάψει να λειτουργούν από το 1947, αλλά μαζί με τις Αλυκές Αλέξανδρου που βρίσκονται κοντά στον όρμο και το λιμάνι Δρέπανο, αποτελούν σημαντικό κομμάτι της ιστορίας του τόπου, που πρέπει να διαφυλαχθεί. Οι πρώτες αλυκές κατασκευάστηκαν από Φράγκους, του Τόκκους, στις αρχές του 15ου αιώνα και είχαν έκταση 500 στρέμματα. Αποτελούνταν από 26 αλοπήγια ή τηγάνια. Επί Ενετών οι αλυκές αυτές τροφοδοτούσαν με αλάτι την πιάτσα της Βενετίας και από εκεί όλες τις αγορές της βόρειας Ιταλίας και της Κεντρικής Ευρώπης. Οι δεύτερες αλυκές δημιουργήθηκαν από τους Ενετούς του Μοροζίνι το 1684 σε έκταση 50 στρεμμάτων με 34 τηγάνια. Οι αλυκές της Λευκάδας έδιναν μεγάλες ποσότητες και καλή ποιότητα αλατιού. Προφυλαγμένες από το κύμα, ήταν ανοιχτές περιοχές με μεγάλη ηλιοφάνεια και ξηρό καλοκαίρι. Το θαλασσινό νερό εξατμιζόταν γρήγορα και άφηνε το αλάτι στον πυθμένα του τηγανιού, έμενε λίγες μέρες και μετά μεταφερόταν στους ώμους και στα κεφάλια εργατών και εργατριών στο μεγάλο κεντρικό σωρό για επεξεργασία και συλλογή στα τέλη Αυγούστου. Ήταν σκληρή κι επικίνδυνη δουλειά για τις εργάτριες που κουβαλούσαν ξυπόλητες πάνω τους 25 με 30 κιλά.', en: 'The Salt Flats: On the other side, to the east, outside the town of Lefkada, there are the salt pans of the town. They have ceased to operate since 1947, but together with the Alexandros salt pans located near the bay and the port of Drepano, they are an important part of the history of the place, which should be preserved. The first salt pans were built by Franks, of Tokki, in the early 15th century and covered an area of 500 acres. They consisted of 26 halopiya or pans. Under the Venetians, these salt works supplied salt to the Venice market and from there to all the markets of northern Italy and Central Europe. The second salt works were created by the Venetians of Morosini in 1684 on an area of 50 hectares with 34 pans. The salt works of Lefkada provided large quantities and good quality salt. Sheltered from the wave, they were open areas with high sunshine and dry summer. The sea water evaporated quickly and left the salt at the bottom of the pan, stayed for a few days and then was carried on the shoulders and heads of workers to the large central pile for processing and collection at the end of August. It was hard and dangerous work for the women workers who carried 25 to 30 kilos barefoot on their backs.' }, { el: 'Το Δάσος των Σκάρων: ένα σημαντικό μνημείο της φύσης στην περιοχή αυτή είναι το δάσος των Σκάρων. Αυτό το δάσος διαθέτει σπάνια χλωρίδα με ένα δυσεύρετο είδος δρυός. Υπάρχουν αρκετά στοιχεία που αναφέρουν ότι το δάσος αυτό ήταν ιδιοκτησία του Τούρκου Αχμέτ Αγά, επί τουρκοκρατίας, ο οποίος το πούλησε αντί ενός ευτελούς ποσού στους ιερείς της Μονής Αγίου Γεωργίου στους Σκάρους.', en: 'The Forest of Scars: an important natural monument in this area is the forest of Skari. This forest has a rare flora with a hard-to-find oak species. There is enough evidence to indicate that this forest was the property of the Turk Ahmet Agha, during the Turkish occupation, who sold it for a paltry sum to the priests of the Monastery of St. George in Skarios.' }] };

export const communityPages: Record<string, PageContent> = {
  'Lefkada': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-1.jpg', paragraphs: [{ el: 'Στο βορειοανατολικό άκρο του νησιού της Λευκάδας πολύ κοντά στην ηπειρωτική ακτή, μόλις περνάμε τη θολωτή γέφυρα, μας υποδέχεται η πρωτεύουσα του νησιού, η Λευκάδα. Η πόλη με τα κεραμόσκεπα, ξυλόδετα κτίρια και το πράσινο τοπίο γύρω της, έχει τη δική της φυσιογνωμία. Η παλιά πόλη έχει μεσαιωνικά χαρακτηριστικά και η ταπεινότητά της συγκινεί τους επισκέπτες.', en: 'At the northeastern end of the island of Lefkada, very close to the mainland coast, as soon as we cross the arched bridge, we are greeted by the capital of the island, the Lefkada. The town with its tiled, timber-framed buildings and the green landscape around it has its own character. The old town has medieval characteristics and its humility touches visitors.' }, { el: 'Λίγο πιο έξω από τη πόλη, το φρούριο της Άγιας Μαύρας, χτισμένο δίπλα στη λιμνοθάλασσα παραμένει ακοίμητος φύλακας και προστάτης της, από τον 14ο αιώνα και έχει πολλά να μας αφηγηθεί. Το φρούριο της Αγίας Μαύρας χτίσθηκε από τους Φράγκους στην αρχική του μορφή το 1300 και αποτελεί υπόδειγμα οχυρωματικής τέχνης. Μάχες με άγριους πειρατές, σθεναρή αντίσταση στους Τούρκους, αλλά και στο χρόνο και στους σεισμούς. Εκεί υψώθηκε η σημαία της Ανεξαρτήτου Επτανήσου Πολιτείας το 1810. Για ένα μεγάλο χρονικό διάστημα τον Αύγουστο μήνα φιλοξένησε τις Γιορτές Λόγου και Τέχνης και το Διεθνές Φεστιβάλ Φολκλόρ.', en: 'Just outside the town, the fortress of Agia Mavra, built next to the lagoon, remains its sleepless guardian and protector since the 14th century and has much to tell us. The fortress of Agia Mavra was built by the Franks in its original form in 1300 and is a model of fortification art. Battles with fierce pirates, fierce resistance to the Turks, but also to time and earthquakes. There the flag of the Independent State of Ionian Islands was raised in 1810. For a long period of time in the month of August it hosted the Literature and Art Festivals and the International Folklore Festival.' }, { el: 'Στο λιμάνι της πόλης είναι συγκεντρωμένες πολλές υπηρεσίες για τη εξυπηρέτηση επισκεπτών, από τα ξενοδοχεία μέχρι τα καΐκια για ημερήσιες εκδρομές στα γύρω νησάκια. Τόπος καθημερινής συνάντησης η κεντρική πλατεία όπου στη δυτική της πλευρά δεσπόζει ο Ναός του Αγίου Σπυρίδωνος που είναι ο πρώτος Ναός της πόλης και χαρακτηρίζεται ως θρησκευτικό, πολιτιστικό και ιστορικό μνημείο. Στη πόλη της Λευκάδας μπορεί να επισκεφθεί κανείς:', en: 'In the port of the town many services are concentrated to serve visitors, from hotels to boats for day trips to the surrounding islands. The central square is the place of daily meeting, where the church of Agios Spyridon, the first church of the city, dominates the western side of the square and is characterized as a religious, cultural and historical monument. In the town of Lefkada one can visit:' }] },
  'Apolpaina': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/09/dimos-leykadas-apolpaina-1.jpg', paragraphs: [{ el: 'Σε απόσταση 2 χλμ. από τη πόλη της Λευκάδας απλώνεται, από τον Ελαιώνα της πόλης ως και τους πρόποδες γραφικότατου λόφου, το χωριό της Απόλπαινας -πιθανόν η ονομασία του χωριού να συνδέεται με τη λατρεία κατά την αρχαιότητα, του «Ιαματικού-Θεραπευτή» Απόλλωνα (Απόλλων + παιάν)-.', en: 'At a distance of 2 km from the town of Lefkada, from the town\'s olive grove to the foot of a picturesque hill, the village of Apolpenas -possibly the name of the village is connected with the cult in antiquity of the «Healer» Apollo (Apollo + paean).' }, { el: 'Η μαρτυρική θυσία του Ιερέα Θεόκλητου Στραβοσκιάδη κατά τη διάρκεια των αγώνων για την Ένωση της Επτανήσου με τη μητέρα Ελλάδα δίνει στο χωριό μια καλή θέση στη νεότερη ιστορία.', en: 'The martyr\'s sacrifice of Priest Theoklitos Stravoskiadis during the struggles for the union of the Ionian Islands with mother Greece gives the village a good place in modern history.' }, { el: 'Στην Απόλπαινα στα δυτικά του χωριού λίγο πριν τη παραλία του Αγίου Ιωάννη (Ιόνιο Πέλαγος) υπάρχει σπήλαιο πλούσιο σε σταλακτίτες , αλλά αναξιοποίητο ακόμη, ειδυλλιακός τόπος για περιπάτους και αναψυχή.', en: 'In Apolpena in the west of the village just before the beach of Agios Ioannis (Ionian Sea) there is cave rich in stalactites , but still unused, an idyllic place for walks and recreation.' }, { el: 'Στα διοικητικά όρια της Απόλπαινας βρίσκεται η μονή της Οδηγήτριας κτισμένη στα μέσα του 15 ου αιώνα από την Ελένη Παλαιολογίνα. Έχει ιδιαίτερα επιμελημένη τοιχοποιία και η εικονογράφησή της θεωρείται σπάνιο δείγμα σύνθεσης βυζαντινής και ιλλυρικής ζωγραφικής . Οι αποτοιχισμένες εικόνες φυλάσσονται στο Βυζαντινό Μουσείο Αθηνών όπου και έχουν εκτεθεί.', en: 'Within the administrative boundaries of Apolpena is the monastery of Hodegetria built in the middle of the 15 th century by Eleni Paleologina. It has particularly curated masonry and its illustration is considered a rare example synthesis of byzantine and illiterate painting . The dismantled icons are kept in the Byzantine Museum of Athens where they have been exhibited.' }] },
  'Katouna': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-lygia.jpg', paragraphs: [{ el: 'Κατούνα: Σε απόσταση 8 χλμ. από τη πόλη της Λευκάδας στον ανατολικό άξονα του νησιού βρίσκεται το χωριό Κατούνα . Παραδοσιακός οικισμός με παλαιά σπίτια και με ιδιαίτερα όμορφη πλατεία στο κέντρο του, γύρω από την οποία υπάρχουν γραφικά ταβερνάκια που προσφέρουν καλό και φθηνό φαγητό. Αξίζει να επισκεφθείτε το χωριό για την καταπληκτική θέα του, τις εκκλησίες με το όμορφο καμπαναριό της Παναγίας, το αξιόλογο τέμπλο και τις θαυμάσιες εικόνες του Αγίου Βάρβαρου. Ένας περίπατος στα καλντερίμια του χωριού θα σας συναρπάσει.', en: 'Katuna: At a distance of 8 km from the town of Lefkada on the eastern axis of the island is the village Katuna . Traditional settlement with old houses and a very beautiful square in the center, around which there are picturesque taverns offering good and cheap food. It is worth visiting the village for its spectacular view, the churches with the beautiful bell tower of Panagia, the remarkable temple and the wonderful icons of Agios Varvaros. A walk along the cobbled streets of the village will fascinate you.' }, { el: 'Λυγιά: 5 χλμ. από την πόλη και 3 από την Κατούνα της οποίας αποτελεί επίνειο βρίσκεται ο οικισμός της Λυγιάς. Είναι ένα μικρό πανέμορφο ψαροχώρι με καθαρές αμμουδιές και καθαρά καταγάλανα νερά τα οποία «αιχμαλωτίζουν τον επισκέπτη».', en: 'Lygia: 5 km from the town and 3 km from Katouna, of which the settlement of Lygia is a port. It is a small beautiful fishing village with clean sandy beaches and clear blue waters that «captivate the visitor».' }, { el: 'Η Λυγιά είναι το δεύτερο σε δυναμικότητα αλιευτικό κέντρο της δυτικής Ελλάδας και λειτουργεί μια από τις πιο σημαντικές ιχθυόσκαλες με πολλά ψαροκάικα και γρι-γρι. Υπάρχουν ξενοδοχεία, ενοικιαζόμενα δωμάτια, ψαροταβέρνες, εστιατόρια, σούπερ μάρκετ και πολλά καταστήματα. Είναι ένα χωριό που σφύζει από ζωή και έχει μεγάλη τουριστική ανάπτυξη. Οι κάτοικοι της είναι ευγενικοί, καλόκαρδοι και φιλόξενοι. Η Λυγιά προσφέρεται για ευχάριστες διακοπές και η παραμονή σας θα σας μείνει αξέχαστη.', en: 'Η Lydia is the second largest fishing center in western Greece and operates one of the most important fish farms with many fishing boats and seiners. There are hotels, rooms to let, fish taverns, restaurants, supermarkets and many shops. It is a village that is full of life and has a great tourist development. Its inhabitants are polite, kind-hearted and hospitable. Lygia is ideal for a pleasant holiday and your stay will be unforgettable.' }] },
  'Kariotes': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-karyotes-1.jpg', paragraphs: [{ el: 'Νέο χωριό, σύγχρονος οικισμός, με ρυμοτομία μεταφερμένο από τη παλιά τοποθεσία για λόγους κατολίσθησης. Απέχει 4 χλμ. από τη πόλη της Λευκάδας. Είναι ένα χωριό «ανθοστόλιστο», «απλόχωρο» και «πρασινοφορούμενο» σύμφωνα με το λαϊκό βάρδο. Οι Καρυώτες βρίσκονται μπροστά στον ιστορικό λόφο «ΚΟΥΛΜΟΣ» (αρχαιολογικός χώρος) στον οποίο βρίσκονται ερείπια από την ακρόπολη της αρχαίας πόλης ΝΗΡΙΚΟΥ πρωτεύουσας του νησιού. Κατά την επίσκεψη σας στους Καρυώτες αξίζει να αναζητήσετε τον χώρο των πρώτων Αλυκών Αλεξάνδρου που δημιουργήθηκαν για πρώτη φορά τον 17ο αιώνα και αποτελούν σημαντικό βιομηχανικό μνημείο.', en: 'New village, modern settlement, with a layout transferred from the old location for landslide reasons. It is 4 km from the town of Lefkada. It is a «flowery», «simple» and «green» village according to the popular bard. The Karyotes are located in front of the historic hill «Koulmos» (archaeological site) where ruins of the acropolis of the ancient city of Nirikos, the capital of the island, are located. During your visit to Karyotes it is worth looking for the site of the first Alexandros Salt Works, which were first created in the 17th century and are an important industrial monument.' }, { el: 'Οι Αλυκές, που ήταν ο δρόμος του αλατιού, λειτούργησαν μέχρι το 1988 διατηρώντας τη δομή των ενετικών σχεδίων. Είναι ένα σύνθετο δημιούργημα ανθρώπινης ενέργειας και φυσικής κατασκευής.', en: 'The Salt Road, which was the salt road, operated until 1988, maintaining the structure of the Venetian plans. It is a complex creation of human energy and natural construction.' }, { el: 'Αποτελούν ιστορική κληρονομιά γιατί παρουσιάζουν κοινωνικό, οικονομικό και τεχνολογικό ενδιαφέρον ,Οι αλυκές έχουν χαρακτηρισθεί από το Υπουργείο Πολιτισμού ως διατηρητέο μνημείο. Ο Δήμος Λευκάδας έχει υποχρέωση για την αναστήλωση των κτιρίων, του χερσαίου χώρου και τη δημιουργία μουσείου Αλυκών και χώρων ψυχαγωγίας.', en: 'They are a historical heritage because they are of social, economic and technological interest, the salt pans have been classified by the Ministry of Culture as a listed monument. The Municipality of Lefkada has an obligation to restore the buildings, the land area and the creation of a Saltworks Museum and recreational areas.' }] },
  'Alexandros': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/09/dimos-leykadas-nikiana.jpg', paragraphs: [{ el: 'Νικιάνα: Ανάμεσα στη Λυγιά και στο Περιγιάλι, 9 χλμ. από τη πόλη της Λευκάδας, βρίσκεται το πανέμορφο γραφικό ψαροχώρι Νικιάνα. Χτισμένο στους πρόποδες του βουνού «Σκάροι» συνδυάζει το πράσινο με το γαλάζιο.', en: 'Nikiana: Between Lygia and Perigiali, 9 km from the town of Lefkada, is the beautiful picturesque fishing village of Nikiana. Built at the foot of the mountain «Skari» combines green and blue.' }, { el: 'Προσφέρει άνεση και ποικιλία στις διακοπές σας αφού μπορείτε να βρείτε σ’ αυτό ότι ζητήσετε.', en: 'It offers comfort and variety in your holidays as you can find everything you need.' }, { el: 'Μέρος ιδανικό για windsurf, water ski, ψάρεμα αλλά και ορειβασία είναι ικανό να προσφέρει στον κάθε επισκέπτη αυτό που αναζητάει.', en: 'Place ideal for windsurfing, water skiing, fishing and mountaineering is able to offer every visitor what they are looking for.' }, { el: 'Λίγο πιο πάνω υπάρχει το ησυχαστήριο των «Αγίων Πατέρων» με πανοραμική θέα.', en: 'A little further up there is the hermitage of the «Holy Fathers» with a panoramic view.' }, { el: 'Αλέξανδρος: Οι κάτοικοι του χωριού Αλέξανδρος, που βρίσκεται στο όρος Σκάροι και αποτελούν ένα σπάνιο γεωφυσικό μνημείο, έχουν μεταφερθεί εδώ και πολλά χρόνια για λόγους επιβίωσης και ανάπτυξης στη παραθαλάσσια περιοχή της Νικιάνας. Στους Σκάρους υπάρχει το γνωστό δάσος από δρύες (βελανιδιές) που είναι και το μοναδικό στα Ιόνια Νησιά. Αξίζει να το επισκεφθείτε.', en: 'Alexander: The inhabitants of the village of Alexandros, located on Mount Skari and constituting a rare geophysical monument, have moved for many years for survival and development reasons to the coastal area of Nikiana. On Scarus there is the famous forest of oaks (oak trees) which is the only one in the Ionian Islands. It is worth visiting.' }] },
  'Tsoukalades': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-tsoykalades.jpg', paragraphs: [{ el: 'Ακολουθώντας τη βορειοδυτική διαδρομή, περνώντας από το κατάφυτο με πεύκα μοναστήρι της Φανερωμένης με την πανοραμική θέα προς το Ιόνιο θα συναντήσετε το χωριό Τσουκαλάδες . Ένα χωριό που έχει ταιριάξει αρμονικά την παράδοση με τον εκσυγχρονισμό και σας προσφέρει ηρεμία και γαλήνη, αλλά και άνεση στις επιλογές σας.', en: 'Following the northwestern route, passing by the pine-clad monastery of Faneromeni with its panoramic view of the Ionian Sea, you will meet the village of Tsoukalades . A village that has harmoniously matched tradition with modernity and offers you peace and tranquility, but also comfort in your choices.' }, { el: 'Το χωριό έχει να παρουσιάσει αξιόλογους ανθρώπους που διέπρεψαν στα Γράμματα, τις Επιστήμες, τις Τέχνες και τον Αθλητισμό. Ενδεικτικά αναφέρουμε τον παγκοσμίου φήμης ζωγράφο Θεόδωρο Στάμο τον διακεκριμένο ιστορικό Πάνο Ροντογιάννη και τον Βαλκανιονίκη Ηλία Βεργίνη.', en: 'The village has to present remarkable people who excelled in Letters, Science, Arts and Sports. Indicatively, we mention the world-famous painter Theodoros Stamos, the distinguished historian Panos Rodogiannis and the Balkan champion Elias Vergini.' }, { el: 'Οι Τσουκαλάδες έχουν μεγάλη αθλητική και πολιτιστική παράδοση, αλλά και στις μέρες μας διατηρεί μια ενδιαφέρουσα πολιτιστική κίνηση και ζωή. Διαθέτει ένα δραστήριο πολιτιστικό σύλλογο με αξιόλογο θεατρικό τμήμα καθώς και χορευτικό. Κάθε Αύγουστο διοργανώνει πολιτιστικές και άλλες εκδηλώσεις που έχουν τίτλο «Βεργίνεια».', en: 'Tsoukalades has a great sporting and cultural tradition, but even nowadays it maintains an interesting cultural movement and life. It has an active cultural club with a remarkable theatre and dance department. Every August it organizes cultural and other events entitled «Vergineia».' }, { el: 'Στην περιοχή των Τσουκαλάδων βρίσκεται η πανέμορφη παραλία Πευκούλια εκεί όπου τα πεύκα κυριολεκτικά αγγίζουν τη πεντακάθαρη γαλανή θάλασσα και δημιουργούν μια εικόνα μαγευτική, μια εικόνα ελευθερίας των αισθήσεων.', en: 'In the area of Tsoukalades is the beautiful beach of Pefkoulia where the pine trees literally touch the crystal clear blue sea and create a magical image, an image of freedom of the senses.' }, { el: 'Το ανεξερεύνητο σπήλαιο του Αι Γιάννη στη περιοχή αποτελεί πρόκληση για όσους αγαπούν την εξερεύνηση. Το πανέμορφο ηλιοβασίλεμα από τη περιοχή του δημοτικού σχολείου του χωριού θα μαγέψει και τους πιο απαιτητικούς επισκέπτες και φυσικά υπάρχει το πευκοδάσος του χωριού που αφήνει άφωνους τους φυσιολάτρες. Αξίζει να περπατήσετε στο χωριό με μια καλή παρέα ή και μόνοι σας.', en: 'The unexplored cave of Agios Ioannis in the area is a challenge for those who love exploration. The beautiful sunset from the area of the primary school of the village will enchant even the most demanding visitors and of course there is the pine forest of the village that leaves nature lovers speechless. It is worth walking around the village with a good company or alone.' }] },
  'Agios Nikitas': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/09/dimos-leykadas-agios-nikitas.jpg', paragraphs: [{ el: 'Στη δυτική πλευρά του Νησιού, 13 χλμ. από τη πόλη της Λευκάδας βρίσκεται ο Άγιος Νικήτας . Γραφικό ψαροχώρι με έντονο γοητευτικό χρώμα, κτισμένο αμφιθεατρικά, έχει εξελιχθεί σε σημαντικό τουριστικό θέρετρο.', en: 'On the west side of the island, 13 km from the town of Lefkada, is the Saint Nikitas . A picturesque fishing village with a strong charming colour, built amphitheatrically, it has developed into an important tourist resort.' }, { el: 'Εδώ η απεραντοσύνη του πελάγους σε συνδυασμό με το απότομο του ορεινού όγκου δημιουργούν μια άλλη αίσθηση. Προσφέρει μεγάλη ποικιλία από ξενοδοχειακά και τουριστικά συγκροτήματα καθώς και όλες τις απαραίτητες ανέσεις για όμορφες και ευχάριστες διακοπές.', en: 'Here the vastness of the sea combined with the steepness of the mountainous terrain create a different feeling. It offers a wide variety of hotel and tourist complexes as well as all the necessary amenities for a beautiful and pleasant holiday.' }, { el: 'Οι δαντελένιες ακρογιαλιές και η καθαρή κρυστάλλινη θάλασσα δημιουργούν μια ωραία αντίθεση με το καταπράσινο τοπίο. Ο πανέμορφος παραδοσιακός οικισμός του Αγίου Νικήτα αποτελεί εκλεκτό πόλο έλξης για ξένους και Έλληνες επισκέπτες.', en: 'The lacy beaches and the clear crystal clear sea create a nice contrast with the green landscape. The beautiful traditional settlement of Agios Nikitas is a magnet for foreign and Greek visitors.' }] },
  'Kalamitsi': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/09/dimos-leykadas-kalamitsi.jpg', paragraphs: [{ el: 'Στην νοτιοανατολική πλευρά της Λευκάδας χτισμένο στη πλαγιά του βουνού Ράχη, 23 χλμ. από τη πόλη της Λευκάδας βρίσκεται το Καλαμίτσι , ένας από τους πιο παραδοσιακούς οικισμούς του Νησιού. Η θέση του, αθέατη από τη πλευρά της θάλασσας, επιλεγμένη έτσι ώστε να προστατεύεται από τις επιδρομές των πειρατών. Κύρια ασχολία των κατοίκων της υπήρξε η καλλιέργεια σιτηρών, λόγος για τον οποίο υπάρχουν ανεμόμυλοι στους τριγύρω λόφους. Από τις παλιές εκκλησίες και ξωκλήσια ξεχωρίζει η Παναγία των Κήπων , κάποτε πλούσιο μοναστήρι.', en: 'On the southeastern side of Lefkada built on the slope of the mountain Rachi, 23 km from the town of Lefkada is the Kalamitsi , one of the most traditional settlements of the island. Its location, unseen from the sea side, chosen to be protected from pirate raids. The main occupation of its inhabitants was the cultivation of cereals, which is why there are windmills on the surrounding hills. Among the old churches and chapels, the most notable is the Virgin Mary of the Gardens , once a rich monastery.' }, { el: 'Από τα υψώματα του χωριού τα βλέμμα του επισκέπτη αναπαύεται στο γαλάζιο του Ιονίου Πελάγους ενώ νοιώθει υπέροχα όταν αντικρίζει τα αστραφτερά γαλαζοπράσινα νερά, τις ξανθές αμμουδιές, τις ομορφότερες στο νησί. Από τις πιο γνωστές και οργανωμένες παραλίες το «Κάθισμα» που έχει βραβευθεί σε διεθνείς διαγωνισμούς. Το μόνο που χωρίζει θάλασσα και βουνό είναι η απέραντη αμμουδιά. Στα δρομάκια του χωριού η ζωή κυλά ακολουθώντας τον παραδοσιακό της ρυθμό και είναι θαυμάσιο ότι θα συναντήσετε γυναίκες ντυμένες με την παλιά λευκαδίτικη φορεσιά, ενώ αξίζει να θαυμάσετε την τέχνη των υφαντών που έχει μια μακρόχρονη παράδοση. Οι κάτοικοι του χωριού είναι ευγενικοί και αυθόρμητοι με τους επισκέπτες του τόπου τους. Ξενοδοχεία, ενοικιαζόμενα δωμάτια, γραφικά ταβερνάκια, εστιατόρια καθώς και καταστήματα με τοπικά προϊόντα σας περιμένουν για να σας χαρίσουν ευχάριστες διακοπές.', en: 'From the heights of the village, the visitor\'s eyes rest on the blue of the Ionian Sea while he feels wonderful when he sees the sparkling turquoise waters, the blond sandy beaches, the most beautiful on the island. One of the most famous and organized beaches is «Kathisma» which has been awarded in international competitions. The only thing that separates sea and mountain is the endless sandy beach. In the streets of the village life flows following its traditional rhythm and it is wonderful that you will meet women dressed in the old Lefkadian costume, while it is worth admiring the art of weavers that has a long tradition. The villagers are kind and spontaneous with visitors to their place. Hotels, rooms to let, picturesque taverns, restaurants and shops with local products are waiting for you to give you a pleasant holiday.' }, { el: 'Το «Καλαμίτσι τ’ όμορφο π’ ανθεί και λουλουδίζει» Ένα ορεινό χωριό του Δήμου Λευκάδας με τρεις ωραίες παραλίες. Το απόγευμα προσφέρει πανέμορφο ηλιοβασίλεμα που είναι ένα από τα πιο «πανηγυρικά» της Λευκάδας.', en: 'The «The beautiful reed that blooms and blossoms’ A mountainous village of the Municipality of Lefkada with three beautiful beaches. In the afternoon it offers a beautiful sunset which is one of the most «solemn» of Lefkada.' }] },
  'Vasiliki': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-vasiliki-1.jpg', paragraphs: [{ el: 'Η Βασιλική έχει γνωρίσει μεγάλη τουριστική ανάπτυξη. Πόλος έλξης η παραλία της Βασιλικής που φτάνει μέχρι την άκρη του κόλπου στην Πόντη και είναι μια από τις καλύτερες της Μεσογείου για το σπορ της ιστιοσανίδας (windsurfing). Είναι σπάνιο να μη φυσάει ο ευνοϊκός μαΐστρος σ’ αυτό τον τόπο.', en: 'Η Vasiliki has experienced great tourist development. The beach of Vasiliki, which reaches the edge of the bay of Ponti and is one of the best in the Mediterranean for the sport of windsurfing, is a major attraction. It is rare that the favorable wind is not blowing in this place.' }, { el: 'Ο άνεμος έρχεται από τα ψηλά κεντρικά βουνά και κατεβαίνει στο κενό της πεδιάδας. Έτσι τα πανιά των ιστιοσανίδων είναι πάντα γεμάτα και αναπτύσσουν μεγάλες ταχύτητες σκίζοντας την καταγάλανη θάλασσα. Εκατοντάδες φανατικοί του σπορ παρατάσσονται καθημερινά κατά μήκος της μεγάλης παραλίας της Βασιλικής και επιδίδονται για ώρες στο αγαπημένο τους άθλημα, προσφέροντας στον επισκέπτη ένα μοναδικό θέαμα.', en: 'The wind comes from the high central mountains and descends into the void of the plain. Thus the sails of the sailboards are always full and develop high speeds, tearing up the deep blue sea. Hundreds of sports fanatics line up daily along the long beach of Vasiliki and indulge for hours in their favourite sport, offering the visitor a unique spectacle.' }, { el: 'Το λιμάνι της Βασιλικής συνδέεται τακτικά με τα νησιά Ιθάκη και Κεφαλονιά εξυπηρετώντας πολλούς τουρίστες που επιθυμούν να γνωρίσουν και άλλα νησιά του Ιονίου. Η περιοχή έχει κατοικηθεί από πολύ νωρίς. Ευρήματα της Παλαιολιθικής και περισσότερα της Νεολιθικής Περιόδου (3.500 π.Χ. περίπου) ανακαλύφθηκαν από έρευνες του Dorpfeld στη Χοιροσπηλιά της Ευγήρου και τα οποία εκτίθενται στο Αρχαιολογικό Μουσείο της Λευκάδας. Στην κοιλάδα της Βασιλικής, σύμφωνα με την Αρχαιολογική Υπηρεσία, υπάρχουν διάσπαρτα αρχαία οικοδομικά λείψανα που ανήκουν πιθανόν σε αρχαία πόλη.', en: 'The port of Vassiliki is regularly connected with the islands of Ithaca and Kefalonia, serving many tourists who wish to visit other islands of the Ionian Sea. The area has been inhabited from very early times. Finds of the Palaeolithic and more of the Neolithic Period (about 3,500 BC) were discovered by Dorpfeld\'s investigations in the Choirospilia of Evgiros and are exhibited in the Archaeological Museum of Lefkada. According to the Archaeological Service, there are scattered ancient building remains in the valley of Vasiliki, which probably belong to an ancient city.' }, { el: 'Από την άλλη πλευρά της Βασιλικής, στα δυτικά, απλώνεται η χερσόνησος και το ακρωτήρι του Λευκάτα. Κατ’ αρχήν θα συναντήσουμε την μικρή παραλία Πλάκα και στη συνέχεια απόκρημνες και πιο εντυπωσιακές δυτικές ακτές του νησιού. Το τοπίο ορεινό και άγριο, κατεβαίνει ως την άκρη της θάλασσας, εκεί που τα κάτασπρα βράχια παλεύουν με το τρικυμισμένο πέλαγος. Άγρια και συναρπαστική η ομορφιά αυτού του τοπίου που ο επισκέπτης πλησιάζει από τη θάλασσα ή από τη στεριά. Εδώ, στη μύτη του Λευκάτα ο μύθος θέλει την ποιήτρια Σαπφώ να δίνει τέλος στη ζωή της απελπισμένη από το πάθος του έρωτα. Αυτά τα λευκά βράχια βάφτισαν και το νησί Λευκάδα. Αυτή είναι μια από τις πολλές εκδοχές για την προέλευση του ονόματός του.', en: 'On the other side of Vasiliki, to the west, lies the peninsula and the cape of Lefkata. First we will meet the small beach of Plaka and then the steep and more impressive western coast of the island. The landscape is mountainous and wild, descending to the edge of the sea, where the white rocks struggle with the stormy sea. Wild and fascinating is the beauty of this landscape that the visitor approaches from the sea or from the land. Here, at the tip of Lefkata, the legend has the poet Sappho ending her life in despair from the passion of love. These white rocks also christened the island of Lefkada. This is one of the many versions of the origin of its name.' }, { el: 'Όλη η περιοχή της Βασιλικής έχει να προσφέρει αξιοθέατα στους επισκέπτες. Έχει τη δυνατότητα αξιοποίησης πολλών μονοπατιών, ενώ προσφέρεται ήδη για ποδηλασία βουνού και για ιππασία.', en: 'The whole area of Vasiliki has attractions to offer to visitors. It has the possibility of utilizing many trails, and is already offered for mountain biking and horseback riding.' }] },
  'Agios Ilias': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-agios-ilias.jpg', paragraphs: [{ el: 'Στα ριζά των βράχων και κάτω από το όμορφο και μοναδικό για την πανοραμική του θέα οροπέδιο της Ελάτης είναι φωλιασμένο το ορεινότερο χωριό της Λευκάδας, ο Άγιος Ηλίας .', en: 'At the roots of the rocks and under the beautiful and unique for its panoramic view plateau of Elati is nestled the most mountainous village of Lefkada, the Saint Elias .' }, { el: 'Εκεί σε οδηγεί ένας φιδωτός ασφαλτοστρωμένος δρόμος 5 χ.μ. πάνω από το Σύβρο, ανάμεσα σε πλούσια βλάστηση.', en: 'A serpentine asphalt road leads you there, 5 km above Syvros, amidst lush vegetation.' }, { el: 'Βορειοδυτικά υψώνεται το ψηλότερο βουνό της Λευκάδας, τα Σταυρωτά. Σε μία από τις χαράδρες του φιλοξενεί το παλιό γραφικό εκκλησάκι της Αγίας Παρασκευής. Είναι η προστάτης και η ελπίδα των απλών κατοίκων του χωριού.', en: 'The highest mountain of Lefkada, Stavrota, rises to the northwest. In one of its gorges is the old picturesque church of Agia Paraskevi. It is the patron saint and the hope of the simple inhabitants of the village.' }, { el: 'Στη μνήμη της, 26 Ιουλίου, το χωριό συνεχίζει την παλιά παράδοση και γιορτάζει με ένα γνήσιο παραδοσιακό τριήμερο πανηγύρι, γνωστό ως το καλύτερο της περιοχής.', en: 'In her memory, on July 26, the village continues the old tradition and celebrates with a genuine traditional three-day festival, known as the best in the region.' }, { el: 'Παλιά οι γύρο βουνοπλαγιές κρατούσαν το καλοκαίρι χιλιάδες γιδοπρόβατα. Σήμερα βόσκουν όσα απόμειναν και χαρίζουν με τα κουδουνίσματα τους και κάποιους ήχους φλογέρας, μια γεύση από τις παλιές ανοιξιάτικες και καλοκαιρινές μαγευτικές βραδιές.', en: 'In the old days the round hillsides used to hold thousands of sheep and goats in the summer. Today they graze what is left and offer with their bells and some flute sounds a taste of the old spring and summer enchanting nights.' }, { el: 'Στο χωρίο λειτουργούν τρία κεντράκια που προσφέρουν στον επισκέπτη τα αγνά και μοναδικά προϊόντα του χωριού κρασί, τυρί και κρέας σε τιμές χαμηλές και με φιλόξενη διάθεση.', en: 'In the village there are three centers that offer to the visitor the pure and unique products of the village wine, cheese and meat at low prices and with a hospitable mood.' }, { el: 'Είναι ένας άριστος τόπος καλοκαιρινής διαμονής.', en: 'It is an excellent place for a summer stay.' }] },
  'Agios Petros': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-agios-petros.jpg', paragraphs: [{ el: 'Πάνω από την Πόντη, στη δυτική άκρη του όρμου της Βασιλικής ο δρόμος ανηφορίζει για τον Άγιο Πέτρο. Από εκεί και μέσω Κομηλιού στρίβει και κατευθύνεται νότια για τα χωριά Δράγανο, Αθάνι και για τις ωραιότερες και πιο φημισμένες παραλίες του νησιού.', en: 'Above Ponti, at the western end of the bay of Vasiliki, the road climbs uphill to Agios Petros. From there and through Komilios it turns and heads south to the villages of Dragano, Athani and the most beautiful and famous beaches of the island.' }, { el: 'Το χωριό Άγιος Πέτρος αποτελείται από έναν αγροτικό οικισμό σε μια όμορφη θέση με εντυπωσιακή θέα προς τον κάμπο της Βασιλικής και προς την κορυφογραμμή των Σταυρωτών, του υψηλότερου βουνού του νησιού. Πήρε το όνομά του από την ομώνυμη εκκλησία του Αγίου Πέτρου, που κτίστηκε το 14ο αιώνα. Είναι το μεγαλύτερο χωριό της περιοχής και οι κάτοικοί τους ασχολούνται με αγροτικές καλλιέργειες.', en: 'The village Saint Peter consists of a rural settlement in a beautiful location with an impressive view of the plain of Vasiliki and the ridge of Stavrotes, the highest mountain of the island. It takes its name from the homonymous church of Agios Petros, built in the 14th century. It is the largest village in the area and its inhabitants are engaged in agricultural farming.' }, { el: 'Η εκκλησία του χωριού, Άγιος Αθανάσιος, ένας ευρύχωρος μονόχωρος ναός με κεραμοσκεπή είναι στο κέντρο του χωριού. Το τέμπλο του, πρόσφατα καθαρισμένο, δείχνει ιδιαίτερα μεγαλόπρεπο. Είναι σε απλή νεοκλασική γραμμή με κυρίαρχα χρώματα, το καφέ και το χρυσαφί. Η εικόνα του Αγίου Αθανασίου, δεσποτική, έργο του Ιωάννη Βολουδάκη από το 1914, στέκει με αυστηρή έκφραση, με χρώματα και τεχνοτροπία επηρεασμένα από την μεταβυζαντινή κρητική παράδοση. Μια ακόμα όμορφη εκκλησία στο χωριό είναι η εκκλησία των Αγίων Αποστόλων με τέμπλο του Ηλία Μεντσικώφ από το 1890. Πρόκειται για καλοδουλεμένη ξυλογλυπτική με φαντασία και τέχνη. Δύο μέτρα από τη δυτική πλευρά του ναού κάτω από το επίπεδο της επιφάνειας του εδάφους, υπάρχει ο κεντρικός χώρος με κόγχη παλαιού ναϊσκου, της Φραγκοκλησιάς. Πρόκειται για ένα ευκτήριο επί Φραγκοκρατίας που σώζεται ακόμα.', en: 'The village church, Agios Athanasios, a spacious one-room church with a tiled roof is in the centre of the village. Its iconostasis, recently cleaned, looks particularly grand. It is in a simple neoclassical line with dominant colours, brown and gold. The icon of St. Athanasios, despotic, the work of Ioannis Voloudakis from 1914, stands with a strict expression, with colors and style influenced by the post-Byzantine Cretan tradition. Another beautiful church in the village is the Church of the Holy Apostles, with an iconostasis by Elias Menchikov from 1890. It is well crafted wood carving with imagination and art. Two meters from the west side of the church below ground level, there is the central area with a niche of an old temple, the Frangokliska. This is a Frankish-era manor house that still survives.' }, { el: 'Το χωριουδάκι του Ρουπακιά διατηρεί τα αγροτόσπιτά του σε καλή κατάσταση. Λιτά, πέτρινα με κεραμο-σκεπές, γερά αλλά μοναχι-κά, στέκουν σαν φύλακες μιας άλλης ξε-χασμένης επο-χής, σκαρφα-λωμένα σε μια απότομη πλαγιά. Δίπλα ο καταρράκτης του Ρουπακιά με νερό που χύνεται ορμητικά κυρίως τους χειμωνιάτικους μήνες. Όλη η περιοχή είναι ξεχωριστής ομορφιάς με σπάνια είδη χλωρίδας, με δάσος, με φαράγγι, με τρεχούμενα νερά και με αξιοποιήσιμα μονοπάτια.', en: 'His little village Rupacia maintains its farmhouses in good condition. Simple, stone-built with tiled roofs, sturdy but lonely, they stand like guardians of another forgotten era, perched on a steep slope. Next to it is the waterfall of Roupakia with water that pours down in a rush, especially in the winter months. The whole area is of special beauty with rare species of flora, forest, gorge, running water and usable paths.' }] },
  'Athani': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-agios-petros-1.jpg', paragraphs: [{ el: 'Λίγο πριν το φάρο, ο δρόμος οδηγεί στο μοναστήρι του Αγίου Νικολάου Ιράς ή Νηράς , ένα αξιόλογο ιστορικό μοναστήρι που ιδρύθηκε πιθανότατα στις αρχές του 17ου αιώνα, το 1637 ή και παλαιότερα. Χτίστηκε από εφτά οικογένειες που αφιέρωσαν μεγάλη ακίνητη περιουσία σ’ αυτό. Ο σημερινός ναός είναι μεταγενέστερος. Το τέμπλο του είναι σύγχρονο με τις εικόνες του που έγιναν το 1799. Δεκατρείς εικόνες του δωδεκαόρτου και τα τρία δεσποτικά είναι έργα του αγιογράφου Ανδρέα Μπέτζου. Είναι όλες ζωγραφισμένες με ειδικό αβγόχρωμα πάνω στο σανίδι και διατηρούνται σε αρκετά καλή κατάσταση. Η δεσποτική εικόνα του Αγίου Νικολάου είναι έργο ενός άλλου γνωστού αγιογράφου, του Δημητρίου Φώσκαρη από το 1699. Είναι η πιο παλιά ενυπόγραφη και χρονολογημένη φορητή εικόνα της Λευκάδας, η οποία κλάπηκε και ξαναβρέθηκε το 1979 με πολλές φθορές. Σήμερα φυλάσσεται σε κτήριο του μοναστηριού στο χωριό Αθάνι . Το μοναστήρι δεν έχει τοιχογραφίες. Ο τελευταίος μοναχός που ασκήτευε εκεί, πέθανε το 1949.', en: 'Just before the lighthouse, the road leads to the monastery of Agios Nikolaos Iras or Niras , a remarkable historical monastery founded probably in the early 17th century, in 1637 or even earlier. It was built by seven families who dedicated a large property to it. The present church is later. Its iconostasis is contemporary with its icons made in 1799. Thirteen twelfth-century icons and three despotic icons are the work of the hagiographer Andreas Betzos. They are all painted with special egg paint on the plank and are all preserved in fairly good condition. The despotic icon of St. Nicholas is the work of another well-known hagiographer, Dimitrios Foskaris from 1699. It is the oldest inscribed and dated portable icon of Lefkada, which was stolen and rediscovered in 1979 with much damage. Today it is kept in a building of the monastery in the village. Athani . The monastery has no frescoes. The last monk who practiced there died in 1949.' }, { el: 'Ο φάρος του Λευκάτα χτίστηκε πάνω σε αρχαίο ναό αφιερωμένο στον Απόλλωνα. Το κυριότερο ιερό της Λευκάδας, το οποίο αναφέρεται συχνά στις αρχαίες πηγές, ήταν αυτό του Απόλλωνα Λευκάτα. Βρίσκεται στο νότιο άκρο του νησιού, στο απόκρημνο ομώνυμο ακρωτήριο που είναι γνωστό ως Δουκάτο ή και, όπως αναφέρεται σε παλιούς ιταλικούς χάρτες, ως Salto di Saffo (άλμα της Σαπφούς). Στην κορυφή του λόφου εντοπίστηκαν από τον W . Dorpfeld λείψανα αρχαίων οικοδομημάτων που ανήκουν στο συγκρότημα του τεμένους, Τη θέση του ναού σήμερα καταλαμβάνει ο σύγχρονος λιθόκτιστος φάρος του Λευκάτα. Σύμφωνα με τους αρχαίους συγγραφείς, οι ανθρωποθυσίες αποτελούσαν το κύριο μέρος των ετήσιων εορτών προς τιμή του Απόλλωνα. Με το πέρασμα του χρόνου έγιναν προσπάθειες μετριασμού αυτής της βάρβαρης συνήθειας. Έτσι φαίνεται ότι κάποια στιγμή, άγνωστο πότε, άρχισαν να χρησιμοποιούν κατάδικους για τις θυσίες.', en: 'The lighthouse of Lefkata was built on an ancient temple dedicated to Apollo. The main sanctuary of Lefkada, which is often mentioned in ancient sources, was that of Apollo Lefkatas. It is located at the southern end of the island, on the steep homonymous promontory known as Dukato or, as it is mentioned on old Italian maps, as Salto di Saffo (Sappho\'s Leap). On the top of the hill, W. Dorpfeld found remains of ancient buildings belonging to the complex of the mosque, The site of the temple is now occupied by the modern stone lighthouse of Lefkata. According to ancient writers, human sacrifices were the main part of the annual festivals in honour of Apollo. Over time, efforts were made to moderate this barbaric custom. Thus it seems that at some point, unknown when, they began to use convicts for the sacrifices.' }, { el: 'Όπως αναφέρει ο Στράβων (1ος αι. π.Χ. – 1ος αι. μ.Χ.) στην ετήσια εορτή του Απόλλωνα επιλεγόταν κάποιος κατάδικος ως εξιλαστήριο θύμα και ριχνόταν από τα βράχια του ακρωτηρίου στη θάλασσα. Τέτοιες εορτές επιζούσαν έως τα ρωμαϊκά χρόνια. Το θύμα επιφορτίζεται όλα τα αρνητικά στοιχεία και τις αμαρτίες της πόλης και με την προσφορά του τις εξαγνίζει.', en: 'As Strabo (1st century BC - 1st century AD) mentions, during the annual festival of Apollo, a convict was chosen as a scapegoat and thrown from the rocks of the cape into the sea. Such feasts survived until Roman times. The victim is charged with all the negative elements and sins of the city and by his offering he purifies them.' }, { el: 'Με τις καθαρτήριες ιδιότητες του Απόλλωνα είναι πολύ πιθανό να συνδέεται και ο θρύλος για την πτώση της Σαπφούς από τα βράχια του Λευκάτα, εξαιτίας ενός αποτυχημένου ερωτά της. Οι αρχαίοι συγγραφείς, με πρώτο τον ποιητή Ανακρέοντα, αναφέρονται συχνά σε επωνύμους και ανώνυμους που έπεσαν από τους βράχους του ακρωτηρίου για να βρουν διέξοδο στα ερωτικά τους πάθη. Έτσι, σε κωμωδίες του 4ου αι. π.Χ. η Λευκάδα εμφανίζεται ως συνώνυμο του ανεπιτυχούς έρωτα και του εξαγνισμού.', en: 'The legend of Sappho\'s fall from the rocks of Lefkata, because of a failed lover, is very likely connected to the purgative properties of Apollo. Ancient writers, beginning with the poet Anacreon, often referred to famous and anonymous people who fell from the cliffs of the cape to find an outlet for their amorous passions. Thus, in 4th century BC comedies, Lefkada appears as a synonym for unsuccessful love and purification.' }, { el: 'Μετά τη νικηφόρο ναυμαχία του Αυγούστου στο Άκτιο (31 π.Χ.) που αποδόθηκε και στη συμβολή του θεού Απόλλωνα, ιερό του οποίου βρισκόταν κοντά στο χώρο της ναυμαχίας, ο Λευκάτας Απόλλωνας ονομάζεται Λευκάδιος και Ακτιακός. «Εν δε τη Λευκάδι άκρα μεν έστιν υψηλή νεώς δε Απόλλωνι ίδρυται και Άκταιον γε αυτόν οι τιμώντες ονομάζουσιν» (Aelianus, De Natura Animalium , XI 8)', en: 'After the victorious naval battle of Augustus at Actium (31 BC), which was attributed to the contribution of the god Apollo, whose sanctuary was located near the site of the battle, Apollo of Lefkatas is called Lefkadios and Aktiakos. «And in Lefkadi there is a high water and Apollo is founded, and those who honour him call him Aktaion» (Aelianus, De Natura Animalium , XI 8).' }, { el: 'Σήμερα ελάχιστα ίχνη του αρχαίου ναού διακρίνονται κάτω από το φάρο. Το τοπίο όμως είναι τόσο εντυπωσιακό, που μεταδίδει στον επισκέπτη τη μαγεία του μυστηριακού χαρακτήρα του.', en: 'Today few traces of the ancient temple can be seen under the lighthouse. But the landscape is so impressive that it conveys to the visitor the magic of its mysterious character.' }] },
  'Vournika': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-voyrnikas.jpg', paragraphs: [{ el: '5 χμλ. από τη Βασιλική βρίσκεται το χωριό Βουρνικά , σ’ ένα ήσυχο και γαλήνιο τοπίο, στη θέση Ροδάκι, απ’ όπου φαίνεται όλος ο κόλπος της Βασιλικής, σώζεται η ερειπωμένη μονή του Αγίου Ιωάννη, μια από τις πιο ενδιαφέρουσες του νησιού. Πιθανολογείται ότι χτίστηκε το 1654.', en: '5 km. from Vasiliki is the village Vurnica , in a quiet and peaceful landscape, in Rodaki, from where the whole bay of Vasiliki can be seen, the ruined monastery of Agios Ioannis, one of the most interesting monasteries of the island, is preserved. It is believed that it was built in 1654.' }, { el: 'Ο ναός είναι χτισμένος πάνω στο δάπεδο μεγάλου αρχαίου δωρικού ναού, αφιερωμένου πιθανότατα στη θεά Δήμητρα, θεά της γεωργίας και της γονιμότητας. Γι’ αυτό και επικράτησε η παράδοση ότι όποιο άτεκνο ζευγάρι λειτουργήσει στην εκκλησία και πατήσει το κατώφλι της εισόδου, αποκτά παιδί. Σώζονται ακόμα ίχνη του αρχαίου ναού, όπως δωρικά κιονόκρανα και μέρος του πλακόστρωτου δαπέδου. Ο αρχικός ναός επεκτάθηκε επανειλημμένα, τα κελιά των μοναχών αυξήθηκαν και δημιουργήθηκαν βοηθητικοί χώροι. Γύρω στα τέλη του 18ου αιώνα το μοναστήρι περιήλθε στο δημόσιο και το 1797 παραχωρήθηκε στη μονή Ασωμάτου της Βαυκερής. Ο ναός διατηρείται σε αρκετά καλή κατάσταση, μέσα σε ευρύχωρο περίβολο. Έχει δύο εισόδους και γυναικωνίτη στο ίδιο επίπεδο με τον κυρίως ναό. Τμήματα των τοιχογραφιών στον ανατολικό τοίχο του ναού διατηρούνται σε καλή κατάσταση και αποτελούν δείγμα εξαίρετης τεχνοτροπίας. Στην κόγχη του ιερού διακρίνεται η αυστηρή μορφή της Πλατυτέρας. Στην πρόθεση εικονίζεται η Άκρα Ταπείνωση, στη συνέχεια ο πρωτομάρτυρας Στέφανος και ο Άγιος Ρωμανός. Παρά την φθορά των παραστάσεων, είναι φανερή η λεπτή, καλαίσθητη τέχνη τους.', en: 'The temple is built on the floor of a large ancient Doric temple, probably dedicated to the goddess Demeter, goddess of agriculture and fertility. That is why the tradition prevailed that any childless couple who attend the church and step on the threshold of the entrance will have a child. Traces of the ancient temple still survive, such as Doric capitals and part of the paved floor. The original church was repeatedly extended, the monks’ cells were enlarged and auxiliary rooms were created. Around the end of the 18th century, the monastery came into public ownership and in 1797 it was ceded to the monastery of Asomatos of Vaukeri. The church is preserved in fairly good condition, within a spacious enclosure. It has two entrances and a women\'s loft on the same level as the main church. Parts of the frescoes on the eastern wall of the church are preserved in good condition and are an example of excellent style. In the niche of the sanctuary, the austere figure of Platytera can be seen. In the front, the Extreme Humiliation is depicted, followed by the first martyr Stephen and St. Romanos. Despite the deterioration of the representations, their delicate, elegant art is evident.' }, { el: 'Στο Βουρνικά υπάρχει επίσης ο ναός του Αγίου Ιωάννη του Προδρόμου. Ήταν ιδιωτικός ναός και ανήκε στην οικογένεια Καραβία. Θεωρείται ως η παλαιότερη εκκλησία των βυζαντινών χρόνων στη Λευκάδα πριν ακόμα από τη μονή της Οδηγήτριας. Πρόκειται για μια μονόκλιτη βασιλική όπως οι περισσότερες εκκλησίες του νησιού, χτισμένη με αργολιθική δομή και ξύλινη στέγη. Στην κόγχη του βόρειου τοίχου αποκαλύφθηκε μορφή άγνωστου Αγίου δεόμενου που ανάγεται στο τέλος του 11ου με αρχές του 12ου αιώνα. Τα υπόλοιπα τοιχογραφικά σύνολα του Αγίου Ιωάννη των Καρααβιάδων είναι νεότερα, του 17ου αιώνα. Η ανατολική πλευρά είναι κατάγραφη. Διακρίνεται στην κατώτερη ζώνη “των Ουρανών η Πλατυτέρα” Η παράσταση της Ανάληψης στο μέτωπο της πλευράς είναι μεγάλη και πολύπλευρη. Οι τοιχογραφίες είναι επηρεασμένες από την κρητική σχολή.', en: 'In Vournika there is also the church of Agios Ioannis the Baptist. It was a private church and belonged to the Karavia family. It is considered to be the oldest church of the Byzantine period in Lefkada, even before the monastery of Odigitria. It is a single-aisled basilica like most of the churches on the island, built with a clay structure and a wooden roof. In the niche of the north wall, a figure of an unknown saint was discovered, dating back to the end of the 11th and beginning of the 12th century. The rest of the frescoes of St. John of the Caraviades are later, from the 17th century. The east side is registered. It is distinguished in the lower zone “of Heaven the Platytera” The representation of the Ascension on the front of the side is large and multifaceted. The frescoes are influenced by the Cretan school.' }] },
  'Dragano': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-dragano.jpg', paragraphs: [{ el: 'Από το Κομηλιό ο δρόμος κατηφορίζει προς τα χωριά Δράγανο και Αθάνι με τα λιθόκτιστα σπιτάκια και τα στενά δρομάκια.τους Στο Δράγανο υπάρχει ένα ελαιοτριβείο που χαρακτηρίζεται ως ιστορικά διατηρητέο μνημείο. Αποτελεί αξιόλογο δείγμα πρωτοβιομηχανικού κτιρίου για την επεξεργασία αγροτικών προϊόντων και είναι σημαντικό στη μελέτη της ιστορίας της αρχιτεκτονικής. Εδώ η επεξεργασία της ελιάς και η παραγωγή του λαδιού γινόταν με χειροκίνητα μέσα ή με τη βοήθεια αλόγου. Στο Δράγανο υπάρχει και ο ναός της Υπαπαντής με αξιόλογες εικόνες των Λευκαδίων αγιογράφων Γαζή και Σίδερη. Εδώ βρίσκονται δύο ενδιαφέροντα συμπλέγματα πηγαδιών από την Τουρκοκρατία, τους Ενετούς, τους Άγγλους και σύγχρονους.', en: 'From Komilio the road descends towards the villages Dragano and Athani with the stone-built houses and the narrow streets.In Dragano there is an olive press that is classified as a historically preserved monument. It is a remarkable example of a proto-industrial building for the processing of agricultural products and is important in the study of the history of architecture. Here the processing of olives and the production of oil was carried out manually or with the help of a horse. In Dragano there is also the temple of Ipapanti with remarkable icons by the Lefkadian hagiographers Gazis and Sideris. Here are two interesting clusters of wells from the Ottoman, Venetian, English and modern times.' }, { el: 'Στο Αθάνι υπάρχει το μοναστήρι του Αγίου Κήρυκου που ιδρύθηκε επί τουρκοκρατίας. Μικρό και περιορισμένο, έγινε μετόχι της μονής του Αρχαγγέλου Ασωμάτου της Βαυκερής το 18ο αιώνα. Γκρεμίστηκε από τους σεισμούς και ξαναχτίστηκε επανειλημμένα. Θύρα της Ωραίας Πύλης που εικονίζει το Χριστό, μια από τις παλαιότερες της μονής, βρίσκεται σήμερα στην εκκλησία της Παναγίας Ραχιώτισσας. Κοντά στη μονή υπάρχουν λείψανα αρχαίου κτιρίου, καθώς επίσης και στη θέση “Σωτήρω”, τα οποία έχει εντοπίσει η Αρχαιολογική Υπηρεσία.', en: 'In Athani there is the monastery of Agios Kirikos, founded during the Turkish occupation. Small and limited, it became a part of the monastery of Archangel Asomatos of Vaukeri in the 18th century. It was demolished by earthquakes and rebuilt repeatedly. The door of the Beautiful Gate depicting Christ, one of the oldest in the monastery, is now in the church of Panagia Rachiotissa. Near the monastery there are remains of an ancient building, as well as at the “Sotiron” site, which have been identified by the Archaeological Service.' }, { el: 'Ο δρόμος από το Αθάνι κατευθύνεται με διακλαδώσεις σε τρεις μοναδικές αμμουδιές, το Γυαλό, τους Εγκρεμνούς και το Πόρτο Κατσίκι. Πρόκειται για παραλίες εκπληκτικής ομορφιάς που η φήμη τους έχει κάνει το γύρο του κόσμου. Πρασινογάλανα, κρυστάλλινα, πεντακάθαρα νερά, με λευκή αμμουδιά, κρυμμένα κάτω από ψηλά απόκρημνα βράχια, αποκαλύπτονται στον επισκέπτη, καθώς εκείνος κατεβαίνει αργά τα αρκετά σκαλοπάτια που τον φέρνουν προς την παραλία. Αυτό το μοναδικό τοπίο είναι τόσο εντυπωσιακό, που χαράζεται για πάντα στη μνήμη όποιου επισκέπτεται τις ακτές αυτές, είτε τις προσεγγίζει από ξηρά, είτε από τη θάλασσα με σκάφος.', en: 'The road from Athani branches off to three unique sandy beaches, Gialos, Egremni and Porto Katsiki. These are beaches of stunning beauty whose reputation has made the rounds of the world. Green-blue, crystal clear, crystal clear waters, with white sandy beaches, hidden under high steep cliffs, are revealed to the visitor as he slowly descends the several steps that bring him to the beach. This unique landscape is so impressive that it is forever engraved in the memory of anyone who visits these shores, whether approaching them by land or by boat from the sea.' }, { el: 'Η πιο γνωστή παραλία, το Πόρτο Κατσίκι, θεωρείται σήμερα μια από τις ξεχωριστές της Ευρώπης, ενώ οι Εγκρεμνοί, κερδίζει κι αυτή καθημερινά τις προτιμήσεις όσων αναζητούν ασυνήθιστης ομορφιάς παραλίες, που αξίζει να γνωρίσει κάθε επισκέπτης του νησιού.', en: 'The most famous beach, Porto Katsiki, is now considered one of the most unique in Europe, while Egremni, is also gaining daily the preferences of those seeking beaches of unusual beauty, which is worth discovering for every visitor to the island.' }] },
  'Evgiros': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-syvota.jpg', paragraphs: [{ el: 'Μετά το Μαραντοχώρι συναντάμε το χωριό Εύγηρος . Εδώ κατά τον Dorpfeld βρίσκεται η Χοιροσπηλιά του Οδυσσέα και ανατολικά ο όμορφος βαθύς όρμος Σύβοτα , που μοιάζει με φιορδ, προσφέρει ασφαλές αγκυροβόλιο σε πολλά σκάφη. Στο μικρό λιμάνι ονομαστές ψαροταβέρνες, από τις καλύτερες του νησιού, που λειτουργούν όλο το χρόνο, συγκεντρώνουν πολλούς ξένους αλλά και ντόπιους.', en: 'After Marantochori we meet the village of Evgiros . Here, according to Dorpfeld, is the Pig Cave of Odysseus and to the east the beautiful deep bay. Sivota , which resembles a fjord, offers a safe anchorage to many boats. In the small harbour, renowned fish taverns, among the best on the island, operating all year round, attract many foreigners and locals.' }] },
  'Komili': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-komilio.jpg', paragraphs: [{ el: 'Μετά τον Άγιο Πέτρο στο δρόμο προσ τις δυτικές παραλίες συναντάμε το Κομηλιό . Στο Κομηλιό ο ναός του Αγίου Αθανασίου χτισμένος στα χρόνια της Τουρκοκρατίας, είναι κρυμμένος σχεδόν μέσα στη γη. Μικρός, φτωχός και χωρίς εικονογράφηση μαρτυρά τα δύσκολα χρόνια εκείνης της εποχής.', en: 'After Agios Petros on the road to the western beaches we meet the Camellia . In Komilios, the church of Agios Athanasios, built during the years of the Ottoman occupation, is almost hidden in the earth. Small, poor and without illustrations, it bears witness to the difficult years of those times.' }] },
  'Kontaraina': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-kontaraina.jpg', paragraphs: [{ el: 'Στον κεντρικό δρόμο από Βασιλική προς Λευκάδα ο δρόμος περνά από το χωριό Κοντάραινα , πολλά από τα σπίτια του οποίου αποτελούν ένα αξιόλογο δείγμα αγροτικών σπιτιών της περιοχής. Στην Κοντάραινα ο επισκέπτης μπορεί να θαυμάσει το ναό της Παναγίας, από τους μεγαλύτερους της υπαίθρου με ύψος που ξεπερνά τα 12 μέτρα. Ο σημερινός ναός είναι από τα μέσα του 19ου αιώνα. Ερείπια του παλαιότερου βρίσκονται στη βορειοανατολική πλευρά του.', en: 'On the main road from Vasiliki to Lefkada the road passes through the village Kontaraena , many of whose houses are a remarkable example of rural houses of the area. In Kontaraina the visitor can admire the church of Panagia, one of the largest in the countryside with a height of more than 12 meters. The current church dates back to the mid-19th century. Ruins of the oldest one are located on its northeastern side.' }, { el: 'Εδώ φυλάσσεται εικόνα της Θεοτόκου, δεσποτική, έργο του Π. Γεννηματά και και ο Χριστός ως Βασιλεύων Βασιλευόντων, ένα σπουδαίο παραδοσιακό έργο του Β.Σιδέρη από το 1870. Μια άλλη δεσποτική εικόνα με εμφανείς δυτικές επιρροές είναι αυτή του Χριστού με τη Μάρθα. Στην ουρανία του ναού ο Ευαγγελιστής Ματθαίος παρακολουθεί τον άγγελό του να του υπογορεύει το ευαγγέλιο. Ακόμα μια όμορφη εκκλησία στην Κοντάραινα είναι ο Άγιος Σπυρίδωνας. Βρίσκεται στο κέντρο του χωριού και μαρτυρά την παλαιότερη ευημερία του τόπου. Το τέμπλο του, έργο του Πάνου Προσαλέντη, είναι απλό, λιτό και με ελαφρά σκαλίσματα. Η εικόνα του Αγίου Σπυρίδωνα είναι του Ιωάννη Αναγνώστη, μάλλον από την Ιθάκη, από το 1776.', en: 'Here is kept an icon of the Virgin Mary, despotic, work of P. Gennimata and Christ as King of Kings, a great traditional work of V. Sideris from 1870. Another despotic icon with obvious western influences is that of Christ with Martha. In the skyline of the church, the Evangelist Matthew watches his angel proclaiming the gospel to him. Another beautiful church in Kontaraina is Agios Spyridon. It is located in the center of the village and testifies to the earlier prosperity of the place. Its iconostasis, the work of Panos Prosalendis, is simple, plain and with light carvings. The icon of Agios Spyridon is by Ioannis Anagnostis, probably from Ithaca, from 1776.' }, { el: 'Περιπλέοντας τις ανατολικές ακτές μετά από τον όρμο της Βασιλικής ο επισκέπτης συναντά δυο θαυμάσιες αμμουδερές παραλίες, η μια καλύτερη από την άλλη. Η πρώτη ονομάζεται Αγιοφύλι και η δεύτερη Αμμούσω. Τα ήρεμα συνήθως και πεντακάθαρα νερά του Ιονίου καλούν τον ταξιδιώτη να δροσιστεί στην αγκαλιά τους.', en: 'Walking along the eastern coast after the bay of Vasiliki, the visitor encounters two wonderful sandy beaches, one better than the other. The first one is called Agiofili and the second one Ammouso. The usually calm and crystal clear waters of the Ionian Sea invite the traveller to cool off in their embrace.' }] },
  'Marantochori': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-marantochori.jpg', paragraphs: [{ el: 'Μετά την Κοντάραινα ο επισκέπτης συναντά το Μαραντοχώρι , ένα κεφαλοχώρι με παράδοση.', en: 'After Contaraena the visitor meets the Marantochori , a village with tradition.' }, { el: 'Κοντά στο χωριό, στη θέση Μπισά υπάρχει το μοναστήρι του Αγίου Γεωργίου. Η ίδρυσή του υπολογίζεται γύρω στα τέλη του 16ου αιώνα με αρχές του 17ου μέχρι το 1620. Το μοναστήρι αυτό δεν ήταν μεγάλο, υπήρξε όμως πλουσιότατο με πολλά κτήματα. Ο μικρός ναός επεκτάθηκε προς τα δυτικά. Ήταν γεμάτος τοιχογραφίες από τις οποίες λίγες σώζονται σήμερα. Το 1922 σύμφωνα με πληροφορίες των κατοίκων, ο ναός έγινε τόπος απομόνωσης ατόμων που είχαν προσβληθεί από ευλογιά. Μετά την επιδημία για απολύμανση σφυροκόπησαν τους τοίχους και τους ασβέστωσαν.', en: 'Near the village, in the place of Bissa, there is the monastery of Agios Georgios. Its foundation is estimated around the end of the 16th century and the beginning of the 17th century until 1620. This monastery was not large, but it was wealthy with many estates. The small church was extended to the west. It was full of frescoes of which few survive today. In 1922, according to local people, the church became a place of isolation for people who had contracted smallpox. After the epidemic for disinfection they hammered the walls and whitewashed them.' }, { el: 'Σώζεται τμήμα του νεότερου τέμπλου αξιόλογης ξυλογλυπτικής τέχνης, από τα μέσα του 18ου αιώνα. Εκεί υπάρχουν δύο αξιόλογες εικόνες, της Θεοτόκου και του Χριστού. Στις θέσεις Μάρμαρα, Πυργί και Κλεισμάτια η Αρχαιολογική Υπηρεσία έχει εντοπίσει λείψανα αρχαίων πύργων. Στην περιοχή βρίσκεται επίσης και μια μικρή φυσική λίμνη, η λίμνη του Μαραντοχωρίου, σημαντικός υδροβιότοπος για πολλά είδη χλωρίδας και πανίδας.', en: 'Part of the newer iconostasis of remarkable woodcarving art from the mid-18th century is preserved. There are two remarkable icons, of the Virgin Mary and Christ. At the sites of Marmara, Pyrgi and Kleismata, the Archaeological Service has identified remains of ancient towers. In the area there is also a small natural lake, the lake of Marantochori, an important wetland for many species of flora and fauna.' }] },
  'Nikolis': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-manasi.jpg', paragraphs: [{ el: 'Ανατολικά από τον κεντρικό δρόμο που κατευθύνεται από τον Άγιο Πέτρο προς τα βόρεια, άλλος μικρότερος δρόμος οδηγεί στο Νικολή και το Μανάση , δύο μικρούς γραφικούς οικισμούς. Τρία χιλιόμετρα περίπου ανατολικά από τη Νικολή υπάρχει η μονή του Αγίου Νικολάου. Κάποτε ήταν το καθολικό μικρού μοναστηριού στην περιοχή. Η μοναδική είσοδος υπάρχει στη νότια πλευρά του ναού και στο υπέρθυρό της υπάρχει λαξεμένος σταυρός με επιγραφή. Ερείπια γύρω από το ναό επιβεβαιώνουν την ύπαρξη της μονής. Σύμφωνα με μια μαρτυρία ο ναός χτίστηκε το 1651.', en: 'Ανατολικά από τον κεντρικό δρόμο που κατευθύνεται από τον Άγιο Πέτρο προς τα βόρεια, άλλος μικρότερος δρόμος οδηγεί στο Νικολή και το Μανάση , δύο μικρούς γραφικούς οικισμούς. Τρία χιλιόμετρα περίπου ανατολικά από τη Νικολή υπάρχει η μονή του Αγίου Νικολάου. Κάποτε ήταν το καθολικό μικρού μοναστηριού στην περιοχή. Η μοναδική είσοδος υπάρχει στη νότια πλευρά του ναού και στο υπέρθυρό της υπάρχει λαξεμένος σταυρός με επιγραφή. Ερείπια γύρω από το ναό επιβεβαιώνουν την ύπαρξη της μονής. Σύμφωνα με μια μαρτυρία ο ναός χτίστηκε το 1651.' }] },
  'Syvros': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-syvros.jpg', paragraphs: [{ el: 'Όλη η περιοχή του Σύβρου παρουσιάζει ιδιαίτερες και ποικίλες ομορφιές. Χαμηλότερα κυριαρχούν οι ελιές, ενώ καθώς το υψόμετρο μεγαλώνει εμφανίζονται αρκετά πλατάνια. Ο τόπος έχει πολλά νερά και αρκετές καλλιέργειες. Σύμφωνα με τα λεγόμενα παλιών αγροτών, ο Σύβρος είχε τους περισσότερους νερόμυλους, 24 συνολικά, για τις ανάγκες των ντόπιων.', en: 'Όλη η περιοχή του Σύβρου παρουσιάζει ιδιαίτερες και ποικίλες ομορφιές. Χαμηλότερα κυριαρχούν οι ελιές, ενώ καθώς το υψόμετρο μεγαλώνει εμφανίζονται αρκετά πλατάνια. Ο τόπος έχει πολλά νερά και αρκετές καλλιέργειες. Σύμφωνα με τα λεγόμενα παλιών αγροτών, ο Sybian είχε τους περισσότερους νερόμυλους, 24 συνολικά, για τις ανάγκες των ντόπιων.' }, { el: 'Εδώ είναι και οι πηγές του φαραγγιού της Κερασιάς, που είναι από τα πιο όμορφα του νησιού. Όσοι αγαπούν τον περίπατο στη φύση σύντομα θα μπορούν να τον απολαύσουν σε μονοπάτια που περιδιαβαίνουν αυτά τα υπέροχα μέρη θαυμάζοντας τις ξεχωριστές φυσικές καλλονές του τόπου, καθώς και το όμορφο δάσος της Δάφνης. Κοντά στο Σύβρο βρίσκεται και η σπηλιά Καρούχα, που αξίζει κανείς να την επισκεφθεί.', en: 'Εδώ είναι και οι πηγές του φαραγγιού της Κερασιάς, που είναι από τα πιο όμορφα του νησιού. Όσοι αγαπούν τον περίπατο στη φύση σύντομα θα μπορούν να τον απολαύσουν σε μονοπάτια που περιδιαβαίνουν αυτά τα υπέροχα μέρη θαυμάζοντας τις ξεχωριστές φυσικές καλλονές του τόπου, καθώς και το όμορφο δάσος της Δάφνης. Κοντά στο Σύβρο βρίσκεται και η σπηλιά Καρούχα, που αξίζει κανείς να την επισκεφθεί.' }] },
  'Chortata': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-chortata.jpg', paragraphs: [{ el: 'Πάνω από το Κομηλιό προς τα βόρεια βρίσκονται τα Χορτάτα , ένα μεγάλο χωριό σε πολύ όμορφη τοποθεσία με εξαιρετική θέα προς τη δύση και το νότο. Η παράδοση θέλει τους κατοίκους του χωριού πρόσφυγες από την Κάτω Ιταλία.', en: 'Above Komilios to the north are the Herb , a large village in a very beautiful location with excellent views to the west and south. Tradition has it that the inhabitants of the village are refugees from southern Italy.' }, { el: 'Η αγορά οκτώ χάλκινων αντικειμένων γεωμετρικών χρόνων από αγρότη της κοινότητας Χορτάτων οδήγησε τον W . Dorpfeld σε μικρή ανασκαφική έρευνα το έτος 1905 στη θέση Σπηλιά. Στις κοιλότητας των βράχων εντοπίστηκαν κατάλοιπα προσφορών, όστρακα αγγείων, τμήματα πήλινων ειδωλίων κλασικών και ελληνιστικών χρόνων και ένα λυχνάρι ρωμαϊκών χρόνων. Η θέση ταυτίστηκε με χώρο τοπικής λατρείας.', en: 'The purchase of eight bronze objects of Geometric times from a farmer of the community of Chortata led W. Dorpfeld to a small excavation in 1905 at the site of Spilia. In the rock cavities, remains of offerings, pottery shells, parts of clay figurines of classical and Hellenistic times and a lamp of Roman times were found. The site was identified as a place of local worship.' }, { el: 'Τα χάλκινα αντικείμενα γεωμετρικών χρόνων, τα οποία αγόρασε ο W . Dorpfeld (περόνη, ιππάριο, διπλοί πελέκεις, περίαπτα), αποτελούν, μέχρι στιγμής, τα μόνα αρχαιολογικά τεκμήρια των πρώιμων ιστορικών χρόνων της Λευκάδας πριν από τον αποικισμό των Κορινθίων.', en: 'The bronze objects of Geometric times, which were purchased by W. Dorpfeld (fork, hipparium, double axes, pendants), are, so far, the only archaeological evidence of the early historical times of Lefkada before the colonization of the Corinthians.' }] },
  'Vafkeri': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-vaykeri.jpg', paragraphs: [{ el: 'Η Βαυκερή όπως και η γειτονική Εγγλουβή αποτέλεσαν το προπύργιο της ορθοδοξίας στα σκοτεινά χρόνια της Τουρκοκρατίας. Τα προνόμια που είχαν από τους Τούρκους, μιας και τους επετράπη να χτίσουν τότε την ιερά μονή του Ασώματου Αρχάγγελου Μιχαήλ, ίσως σε κάποιο βαθμό να εκφράζουν το πνεύμα του αγώνα και της αντίστασης των κατοίκων οι οποίοι το 1940 έκαναν όλο τον κόσμο να υποκλιθεί μπροστά στο μεγαλείο τους, γράφοντας πρωτοσέλιδα στις εφημερίδες για τo αντιστασιακό τους πνεύμα. Η μικρότερη γωνιά γης στον πλανήτη αντιστάθηκε σε μια αυτοκρατορία. Αφόπλισαν και αιχμαλώτισαν τους Ιταλούς καραμπινιέρους που πήγαν στο χωριό για είσπραξη φόρων. Ήτανε η πρώτη μορφή αντίστασης ενάντια στους κατακτητές κι ο κόσμος υποκλίθηκε σε αυτούς που εν αγνοία τους – για το μεγαλείο των πράξεων τους – τότε έγραφαν αυτές τις ιστορικές στιγμές.', en: 'Η Baukeri as well as the neighbouring Englouvi were the bastion of Orthodoxy during the dark years of the Ottoman rule. The privileges they had from the Turks, since they were allowed to build the holy monastery of the Incorruptible Archangel Michael, may to some extent express the spirit of struggle and resistance of the inhabitants who in 1940 made the whole world bow before their greatness, writing headlines in the newspapers about their resistance spirit. The smallest corner of the planet resisted an empire. They disarmed and captured Italian carabinieri who went to the village to collect taxes. It was the first form of resistance against the conquerors and the world bowed to those who unknowingly - for the greatness of their actions - were then writing these historic moments.' }, { el: 'Σήμερα η Βαυκερή μπορεί να έχει μείνει με ελάχιστους κατοίκους, μιας και αποίκησαν τα δυο χωριά που βρίσκονται στους πρόποδες του βουνού και στον κάμπο, την Ράχη και το Νυδρί όμως δεν έχουν χάσει το οικιστικό πολιτιστικό τους χαρακτήρα. Τα περισσότερα σπίτια είναι πέτρινα κι ότι χτίζεται φέρει τη σφραγίδα του παραδοσιακού. Ο επισκέπτης μπαίνει σε ένα χωριό που τον φέρνει νοερά στο 1500 ή στο 1600. κι όταν περνάει από τον πλάτανο ή τη βρύση του χωριού τον συνοδεύουν νοερά οι οπτασίες των Καρνάτιδων που με τις πινιάτες και τα σκαρίδια στο κεφάλι σηκώνονταν με το ξημέρωμα για να σφυρηλατήσουν με τις εργασίες τους το οικονομικό και πολιτιστικό γίγνεσθαι της περιοχής.', en: 'Today, Vaukeri may have remained with few inhabitants, since the two villages located at the foot of the mountain and the plain, Rachi and Nydri, have been colonized, but they have not lost their residential and cultural character. Most of the houses are made of stone and everything that is built bears the stamp of the traditional. The visitor enters a village that takes him mentally back to the 1500s or 1600s, and when he passes by the plane tree or the village fountain, he is mentally accompanied by the visions of the Carnatic women who, with their pinyates and scarabs on their heads, rose at dawn to forge the economic and cultural life of the region with their work.' }] },
  'Vlycho': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-vlycho.jpg', paragraphs: [{ el: 'Η ονομασία Βλυχό προέρχεται από τις περίπου 30 βλύχες που αναβλύζουν νερό κατά μήκος του βουνού της Αμαλής στους πρόποδες του οποίου είναι χτισμένο.', en: 'The name Vlicho comes from the 30 or so water gushing out of the mountain of Amalis at the foot of which it is built.' }, { el: 'ΙΣΤΟΡΙΑ', en: 'HISTORY' }, { el: 'Το Βλυχό αποτέλεσε επί 600 χρόνια τόπο που κληρονομούνταν από τον ένα κατακτητή στον άλλον. Στα χρόνια της Τουρκοκρατίας 1479-1684 ανήκε σε Τούρκους πασάδες. Στα χρόνια των Ενετών 1684-1789, μοιράστηκε σε φεουδάρχες που πολεμούσαν στο πλευρό των Ενετών κατά των Τούρκων όπως ήτων οι Τσαλαμπαίοι, Μαχαιραίοι, Δίπλας, Κόντε Καββαδάς, Βαλαωριταίοι κ.α.', en: 'For 600 years Vlyho was a place that was inherited from one conqueror to another. During the years of the Turkish occupation 1479-1684 it belonged to the Turkish Pasades. During the Venetian years 1684-1789, it was divided among feudal lords who fought on the side of the Venetians against the Turks, such as the Chalampaioi, Machairaioi, Diplas, Kode Kavvadas, Valaoritai, etc.' }, { el: 'Σε αντίστοιχους προγόνους αυτών πέρασαν και στα επόμενα χρόνια των Άγγλων, Γάλλων, Ρωσοτούρκων αλλά και Ελλήνων.', en: 'In the following years they passed to similar ancestors of the English, the French, the Russo-Turks and the Greeks.' }, { el: 'Το κατά καιρούς καθεστώς των κατακτητών εξυπηρετούσε πάντα την τάξη των ευγενών επειδή μέσω αυτών ασκούνταν με μεγαλύτερη αποτελεσματικότητα η εξουσία προς τις κατώτερες κοινωνικές τάξεις.', en: 'The regime of the conquerors from time to time always served the noble class because through them power was exercised more effectively towards the lower social classes.' }, { el: 'Ο λαός που βρέθηκε με περιουσία στο Βλυχό – όπως και στο Γενί- δεν απέκτησε τίποτε από δωρεές. Εξαγόρασε την γη αυτή με αίμα και ιδρώτα. Πρώτα με την προσωπική εργασία του μιας και την μίσθωνε από τους άρχοντες και λίγο λίγο την αγόρασε.', en: 'The people who found themselves with property in Vlyho - as in Yeni - acquired nothing from donations. They bought this land with blood and sweat. First with his personal labour since he leased it from the lords and little by little he bought it.' }, { el: 'Έπειτα με τα εμβάσματα που έστελναν οι χωριανοί από την Αμερική. Μέχρι το 1950 γύριζε ο φοροεισπράκτορας της οικογένειας Βαλαωρίτη στη θάλασσα του Βλυχού και Νυδρίου κι από ότι ψάρια είχαν τα καΐκια μαζί τους, τους έπαιρνε το «αναλογούν» φόρο μιας και η θάλασσα ήταν του Βαλαωρίτη.', en: 'Then with the remittances sent by the villagers from America. Until 1950, the tax collector of the Valaoritis family would return to the sea of Vlychos and Nidri and from whatever fish the boats had with them, he would take the «proportional» tax since the sea was Valaoritis\'.' }, { el: 'Το Βλυχό φαίνεται να κατοικούνταν πάντα ανά τους αιώνες από διάφορους κατακτητές. Σαν χωριό όμως με συνείδηση κοινή άρχισε να διαμορφώνεται από το 1850 κι εδώ. Ευτράπελες διηγήσεις που σώζονται στα αρχεία της αστυνομίας Κατωχωρίου μιλάνε για την αντιπαλότητα μεταξύ των δύο πρώτων εμπορικών μαγαζιών που υπήρχαν τότε στο Βλυχό και συναγωνίζονταν το ένα το άλλο σε κατανάλωση.', en: 'Vlyho seems to have been inhabited throughout the centuries by various conquerors. But as a village with a common consciousness, it began to take shape from 1850 onwards. Unflattering stories preserved in the archives of the Katochori police speak of the rivalry between the first two commercial shops that existed in Vlyho at that time and competed with each other in consumption.' }, { el: 'Σαν χωριό το Βλυχό έφτασε στην κορυφή του από το 1910 έως το 1940. Δέκα τουλάχιστον μεγάλα εμπορικά της εποχής διακινούσαν πλήθος εμπορευμάτων προς και από το νησί. Στο Βλυχό χτυπούσε ο οικοδομικός παλμός όλου του νησιού. Ο δε έμπορος Γιάννης Σκλαβενίτης θεωρούνταν ένας από μεγαλύτερους εμπόρους της Δυτικής Ελλάδας. Τελικά όλα έσβησαν με τον πόλεμο του 1940.', en: 'As a village, Vlyho reached its peak from 1910 to 1940. At least ten large merchant ships of the time moved numerous goods to and from the island. Vlyho was the pulse of the construction industry of the whole island. The merchant Yannis Sklavenitis was considered one of the biggest merchants of Western Greece. Eventually everything faded away with the war of 1940.' }, { el: 'Σήμερα – αν κι έχουν γίνει σημαντικά έργα στο χώρο της υλικοτεχνικής υποδομής- φαίνεται ότι αναζητεί την σπίθα που θα ανάψει πάλι την ανάπτυξη στην περιοχή μιας και αποτελεί το Βλυχό ένα εντυπωσιακής ομορφιάς μνημείο φυσικού κάλλους και έναν εκλεκτό πόλο έλξης .', en: 'Today - although significant works have been done in the area of logistical infrastructure - it seems that it is looking for the spark that will reignite the development in the area since Vlyho is a monument of natural beauty and an exquisite attraction.' }] },
  'Katochori': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-katochori.jpg', paragraphs: [{ el: 'Το Κατωχώρι αποτελεί την πολιτιστική έδρα του δήμου Ελλομένου –τιμής ένεκεν- επειδή υπήρξε η έδρα του πρώην δήμου Ελλομένου μεταξύ 1866-1912.', en: 'The Katochori is the cultural seat of the municipality of Elloimeno -in honor- because it was the seat of the former municipality of Elloimeno between 1866-1912.' }, { el: 'Στις μέρες μας έχει 150 μόνιμους κατοίκους έναντι των 1005 που είχε φτάσει το 1907. Τις μέρες της ακμής του, μας τον θυμίζουν τα τέσσερα παλιά δημαρχιακά κτίρια, οι παλιές φυλακές, οι παλιοί αστυνομικοί σταθμοί, τα 12 ελαιοτριβεία και οι 10 εκκλησίες.', en: 'Nowadays it has 150 permanent residents compared to 1005 in 1907. The four old town hall buildings, the old prison, the old police stations, the 12 mills and the 10 churches remind us of its heyday.' }, { el: 'Ο Άγιος Χαράλαμπος συγκεκριμένα με το πέτρινο ταμπλό ανάγεται στον 15 ο αιώνα ενώ έργο τέχνης θεωρείται και το τέμπλο του Άγιου Δημήτριου που σκάλισε το 1731 ο Μαστρομανώλης ο Αρκαδιανός, καθώς και οι δεσποτικές εικόνες της ίδιας περιόδου που είναι φιλοτεχνημένες από Αγιορείτες μοναχούς.', en: 'Agios Charalambos in particular with the stone tableau dates back to the 15th century. ο century, while the iconostasis of Saint Demetrios carved in 1731 by Mastromanolis the Arcadian, as well as the despotic icons of the same period, which were carved by monks of the Mount Athos order, are also considered works of art.' }, { el: 'Στους χώρους των φυσικών καλλονών υπάρχει ακόμα ο πλάτανος του Αγίου Νικολάου με 6,50 μέτρα περιφέρεια, ο γκρεμός βάθους 150 μέτρων που σχηματίστηκε το 1918 στη θέση Πορτί μετά από κατολίσθηση του βουνού, το δάσος που φυτεύτηκε από τα παιδιά του δημοτικού σχολείου το 1953 και πλήθος αξιόλογων πέτρινων κτιρίων της περιόδου 1880 – 1900 που το χωριό γνώρισε την μέγιστη ακμή λόγω της αμπελοκαλλιέργειας που υπήρχε και της εξαγωγής του κρασιού στη Γαλλία.', en: 'In the areas of natural beauty there is also the plane tree of Agios Nikolaos with a circumference of 6.50 meters, the 150 meters deep cliff formed in 1918 in the position of Portee after a landslide of the mountain, the forest planted by the children of the primary school in 1953 and a number of remarkable stone buildings of the period 1880 - 1900 when the village experienced its greatest prosperity due to the vineyard and the export of wine to France.' }, { el: 'Επίσης αυτούσιο σώζεται το αρχοντικό του Κόντε Καββαδά από το 1700 ο οποίος διετέλεσε πρώτος έπαρχος του νησιού της Λευκάδας. Τα σίδερα της λαιμητόμου που βρίσκονταν στημένα έξω από το σπίτι του μέχρι το 1880 υπάρχουν κι αναμένουν αναστήλωση.', en: 'The mansion of Conte Kavvadas from 1700, who was the first prefect of the island of Lefkada, is also preserved unchanged. The irons of the guillotine that were set up outside his house until 1880 are still there and await restoration.' }, { el: 'ΛΑΟΓΡΑΦΙΑ', en: 'LAYOUT' }, { el: 'Οι κάτοικοι του χωριού ανέκαθεν διακρίνονταν για την έφεση προς τα γλέντια, την διασκέδαση, το χορό και γενικά την ελεύθερη ζωή. Δεν υπήρχε πνευματική ανάπτυξη και πρόοδος αντίστοιχη με άλλα χωριά του νησιού. Στις μέρες μας είναι ακόμη πιο θολά τα πράγματα γιατί αρχίζει να αλλάζει κι η σύνθεση του πληθυσμού και να κυριαρχούν καινούργιοι προβληματισμοί ως προς την βιωσιμότητα των νέων της περιοχής.', en: 'The inhabitants of the village have always been distinguished for their penchant for parties, entertainment, dancing and generally free life. There was no spiritual development and progress comparable to other villages on the island. Nowadays things are even more blurred because the composition of the population is changing and new concerns about the sustainability of the young people of the area are beginning to dominate.' }, { el: 'ΟΝΟΜΑΣΙΑ', en: 'NAME' }, { el: 'Το Κατωχώρι στην σημερινή του θέση ξεκίνησε το 1601 όταν εγκαταστάθηκε η πρώτη οικογένεια. Υπήρχε όμως στους πρόποδες του λόφου παλιό χωριό το οποίο καταστράφηκε τον Μεσαίωνα πιθανόν από πειρατές. Επειδή το χωριό αυτό το παλιό ονομαζόταν Κατωχώρι με το ίδιο όνομα έβγαλαν και το καινούργιο μιας κι ο λόφος πάνω στον οποίο χτίστηκε ήτανε περιοχή του παλιού χωριού.', en: 'Katochori in its current location began in 1601 when the first family settled. But there was an old village at the foot of the hill which was destroyed in the Middle Ages, probably by pirates. Because this old village was called Katochori, the new village was named with the same name, since the hill on which it was built was the area of the old village.' }, { el: 'Το παλιό αυτό χωριό είναι χτισμένο πάνω στα ερείπια της αρχαίας πόλης του «Ελλόμενου» εξού και το όνομα του Δήμου. Την αρχαία αυτή πόλη κατέστρεψαν οι Αθηναίοι όταν έκαναν την εκστρατεία στις Συρακούσες επειδή οι Ελλόμενιοι ήτανε σύμμαχοι των Κορινθίων που αποικούσαν την Λευκάδα.', en: 'This old village is built on the ruins of the ancient city of «Ellomenos» hence the name of the municipality. This ancient city was destroyed by the Athenians when they campaigned in Syracuse because the Elloumenians were allies of the Corinthians who were colonizing Lefkada.' }, { el: 'Από την αρχαία πόλη του Ελλομένου σώζονται οι βάσεις του πύργου του 7 ου αιώνα π.Χ. στη θέση Ξυλογαϊδάρα. Η θέση Ξυλογαϊδάρα συγκεκριμένα ήτανε ένα τεράστιο ξύλινο σκαρίδι μέσα στο οποίο έβαζαν το θύμα του είχαν μαστιγώσει μέχρι να ανοίξουν πληγές στο σώμα του, έριχναν αλάτι και πάνω από το αλάτι ζεματιστό νερό μέχρι να μαρτυρήσει ή μέχρι να πεθάνει.', en: 'The bases of the tower of the ancient city of Ellomenos are preserved 7 th century BC at the site of Xylogoidara. The Xylogoidara site in particular was a huge wooden stool in which the victim was put, whipped until wounds opened in his body, salt was poured and over the salt scalding water was poured until he was martyred or until he died.' }, { el: 'ΤΟ ΚΑΤΩΧΩΡΙ ΣΗΜΕΡΑ', en: 'THE DOWNHILL TODAY' }, { el: 'Το Κατωχώρι σήμερα κι αφού έκλεισε 400 χρόνια εγκατεστημένο στο χώρο που ουσιαστικά του επέβαλλαν οι τότε Τούρκοι κατακτητές, ατενίζει μπροστά του το θολό τοπίο και τίποτε άλλο.', en: 'Katochori today, after 400 years of being established in the area that the then Turkish conquerors essentially imposed on it, is looking at a blurred landscape and nothing else.' }, { el: 'Σε όλη την περιφέρεια που μέχρι το 1912 ανήκε στο Κατωχώρι τώρα δημιουργήθηκαν ακόμη τα εξής χωριά: Βλυχό, Γένι, Προλιθιά. Επίσης οικισμοί δημιουργούνται στον Κορακιά, στη Δεσίμι και στην Καραβόλιμπα.', en: 'In the whole region that until 1912 belonged to Katochori, the following villages were created: Vlyho, Geni, Prolithia. Also settlements were created in Korakias, Desimi and Karavoliba.' }, { el: 'Όλοι οι νέοι οικισμοί έχουν αυξητικές τάσεις ενώ το Κατωχώρι φαντάζει πλέον σαν μουντό τοπίο με πλούσιο παρελθόν, φτωχό παρόν κι αβέβαιο μέλλον.', en: 'All the new settlements have increasing trends while Katochori now looks like a dull landscape with a rich past, a poor present and an uncertain future.' }] },
  'Neochori': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-neochori.jpg', paragraphs: [{ el: 'Σίγουρα κάποτε θα υπήρχε και “Νέο”-χώρι αν κρίνουμε από το όνομα του. Όμως στις μέρες μας αποτελεί ένα παλιό χωριό.', en: 'Surely at one time there would have been a “Neo” village, judging by its name. But nowadays it is an old village.' }, { el: 'Η αλήθεια είναι ότι στα χρόνια της δικτατορίας (1967 – 1974) το χωρίο εγκαταλείφθηκε από του ντόπιους κατοίκους, που αναζήτησαν την τύχη τους στους πρόποδες του βουνού και συγκεκριμένα στις τοποθεσίες Παλαιοκατούνα και Μεγάλο Αυλάκι, εκμεταλλευόμενοι τις δυνατότητες για οικονομική ανάπτυξη.', en: 'The truth is that during the years of the dictatorship (1967 - 1974) the village was abandoned by the local inhabitants, who sought their fortune in the foothills of the mountain and specifically in the locations of Paleokatouna and Megalo Avlaki, taking advantage of the opportunities for economic development.' }, { el: 'Την δεκαετία όμως του 1980 μια ομάδα νέων ανθρώπων – αμφισβητίες των πόλεων- κατά άλλους, αγόρασαν παλιά σπίτια του χωριού τα οποία τα επισκεύασαν σεβόμενοι απόλυτα το παραδοσιακό χρώμα του χωριού. Με την ευαισθησία που χειρίστηκαν τον κοινόβιο χώρο τους, τον έκαναν να αποτελεί αξιοπρόσεχτο τουριστικό προορισμό.', en: 'In the 1980s, however, a group of young people - urban challengers, according to others - bought old houses in the village and repaired them, fully respecting the traditional colour of the village. With the sensitivity with which they handled their communal space, they made it a remarkable tourist destination.' }, { el: 'Εκτός από τα παραδοσιακά σπίτια και την εντυπωσιακή θέα προς τον κάμπο του νησιού ο επισκέπτης μπορεί να δει ακόμα και την Παναγία την Ευαγγελίστρια, μοναδική εκκλησία με τρούλο στο νησί καθώς και το ιδιωτικό μουσείο του Παναγιώτη Τσατσούλα το οποίο περιέχει αντίγραφα μουσικών οργάνων από την αρχαιότητα μέχρι τις μέρες μας καθώς και τον πλούτο λαογραφικού υλικού.', en: 'Apart from the traditional houses and the impressive view of the plain of the island, the visitor can see even the Panagia Evangelistria, the only church with a dome on the island, as well as the private museum of Panagiotis Tsatsoulas which contains copies of musical instruments from antiquity to the present day and a wealth of folklore material.' }, { el: 'Από το Νεοχώρι κατάγεται ο κλαριντζής Κώστας Γκιαούζος – Μουζάκης που προπολεμικά μέχρι το 1950 θεωρούνταν ένα από τα καλύτερα κλαρίνα της Ελλάδας.', en: 'From Neochori comes the clarinetist Kostas Giaouzos - Mouzakis, who before the war until 1950 was considered one of the best clarinets in Greece.' }] },
  'Nydri': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-nydri-1.jpg', paragraphs: [{ el: 'Η ευρύτερη τουριστική περιοχή του κάμπου του Νυδρίου αποτελεί έναν συνολικό χώρο εξέτασης, μιας και δεν υπάρχουν στις μέρες μας τα διαχωριστικά που υπήρχαν παλιά.', en: 'The wider tourist area of the Nydri plain is a total area of examination, since the divisions that used to exist in the past do not exist nowadays.' }, { el: 'Στις αρχές του αιώνα συγκεκριμένα, υπήρχαν σ’ όλο αυτό τον χώρο των δύο χιλιομέτρων έξι σπίτια! Δύο στο Στενό και τέσσερα στο Νυδρί.', en: 'At the beginning of the century in particular, there were six houses in this two-kilometre area! Two in Steno and four in Nidri.' }, { el: 'Στα πλαίσια της τουριστικής ανάπτυξης η προνομιούχα θέση όμως της περιοχής δεν άργησε να την κάνει να ξεχωρίσει.', en: 'In the context of tourism development, however, the privileged position of the area did not take long to make it stand out.' }, { el: 'Ήδη από τις αρχές του αιώνα, ο Γερμανός αρχαιολόγος Γουλιέλμος Δαιρπφελδ ξεκίνησε ανασκαφές στην περιοχή του Στενού επιδιώκοντας να επιβεβαιώσει την θεωρία του περί Ομηρικής Ιθάκης την οποία μόνο αυτός πίστευε τότε.', en: 'Already at the beginning of the century, the German archaeologist William Deirpfeld began excavations in the area of the Strait, seeking to confirm his theory of Homer\'s Ithaca, which only he believed at the time.' }, { el: 'Ο Σλήμαν συνεργάτης του Δαιρπφελδ ανέλαβε τις ανασκαφές στην Τροία που τον έκαναν διάσημο ενώ ο Δαίρπφελδ δεν μπόρεσε να βρει τίποτε περισσότερο από δείγματα της πρώιμης εποχής του χαλκού (2000 π.Χ).', en: 'Schliemann, a colleague of Deirpfeld, undertook the excavations in Troy that made him famous, while Deirpfeld could find nothing more than samples of the early Bronze Age (2000 BC).' }, { el: 'Το μυστικό της Ομηρικής Ιθάκης και του παλατιού του Οδυσσέα φαίνεται ότι καλά κρατεί. Ίσως οι θρύλοι και οι παραδόσεις του απλού κόσμου που μιλούν για το χρυσό αργαλειό της Πηνελόπης ο οποίος βρίσκεται στον κόλπο του Βλυχού, να χρήζουν για μελλοντικές – ενάλιες – ανασκαφές.', en: 'The secret of Homer\'s Ithaca and the palace of Odysseus seems to be well kept. Perhaps the legends and traditions of the common people that speak of Penelope\'s golden loom, which is located in the bay of Vlychos, are worthy of future - inland - excavations.' }, { el: 'Πάντως η επίσκεχη τιυ αυτοκράτορα της Αυτροουγγαρίας, Βίλχελμ Κάιζερ στο Νυδρί στις ράχες του αιώνα (1917) ήτανε η αρχή που προοιώνιζε το μέλλον της περιοχής ως τις «Κάννες» της Λευκάδας.', en: 'However, the visit of the Emperor of Austria-Hungary, Wilhelm Kaiser, to Nydri at the turn of the century (1917) was the beginning that foreshadowed the future of the region as the «Cannes» of Lefkada.' }, { el: 'Όλο το «JET SET» των διάσημων προσωπικοτήτων που παρέλασαν από την περιοχή, αρχή γενομένης από τον Αριστοτέλη Ωνάση που αγόρασε το νησάκι «Σκορπιος» καθώς και οι αρχηγοί κρατών όπως και οι άλλες προσωπικότητες των διαφόρων χωρών που κατά καιρούς κατακλύζουν την περιοχή, έχουν δημιουργήσει τουριστικό ρεύμα που αυξάνετε χρόνο με το χρόνο.', en: 'All the «JET SET» of famous personalities that have paraded through the area, starting from Aristotle Onassis who bought the island «Skorpios» as well as the heads of state and other personalities of various countries that occasionally flood the area, have created a tourist stream that increases year after year.' }] },
  'Platystoma': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-platystoma.jpg', paragraphs: [{ el: 'Τα Πλατύστομα υπήρξαν κι αυτά ως χωριό κατάλοιπο της Τουρκοκρατίας και των κατά καιρούς κατακτητών. Μετά την ένωση της Επτανήσου με την Ελλάδα αρχίσανε να τα εγκαταλείπουν σιγά – σιγά οι κάτοικοι του. Μαζικότερη μετακίνηση όμως των κατοίκων τα τελευταία 40 χρόνια προς το επίνειό του το Περιγιάλι, δίνουνε στα Πλατύστομα σήμερα εικόνα εγκατάλειψης.', en: 'The Platypus were also a remnant village of the Turkish occupation and the occasional conquerors. After the union of the Ionian Islands with Greece, its inhabitants began to slowly abandon it. However, the massive movement of the inhabitants in the last 40 years to the village of Perigiali, give Platystoma today a picture of abandonment.' }, { el: 'Από τα Πλατύστομα κατάγονταν ο επίσκοπος Άρτας Κατωχιανός κατά τα χρόνια του Αλή Πασά. Επίσης από εκεί κατάγονταν κι ο περίφημος ληστής Ψίλιας που έδρασε στα τέλη του 19 ου αιώνα όπου η ληστοκρατία αποτελούσε τότε ηρωικό τρόπο ζωής.', en: 'The bishop of Arta, Katochianos, descended from Platystoma during the years of Ali Pasha. Also from there came the famous bandit Psilias who was active at the end of the 19th century. th century where banditry was then a heroic way of life.' }, { el: 'Στην παλιά διοικητική διαίρεση 1866 – 1912 ανήκε στο δήμο Καρυάς ενώ τώρα λόγω του Περιγιαλιού του οποίου αποτελεί περιοχή του, τοποθετήθηκε στον Ελλομένο.', en: 'In the old administrative division 1866 - 1912 it belonged to the municipality of Karya, while now, due to the perigliou which is its area, it was placed in Elloimeno.' }, { el: 'Το μοναστήρι της Κόκκινης Εκκλησίας το οποίο ανήκει στα Πλατύστομα γνώρισε μεγάλη ακμή στους 15 ο και 19 ο αιώνα.', en: 'The monastery of the Red Church which belongs to Platystoma flourished in the 15th century. ο and 19 ο century.' }, { el: 'Μέρος της αίγλης του σώζεται ακόμη και σήμερα που μπορεί ο επισκέπτης να δει από τον περίβολο και τα κελιά έως τους χώρους και τον κύριο ναό. Το όνομά του οφείλεται κυρίως στο κοκκινόχωμα που χρησιμοποιήθηκε ως κονίαμα για την κατασκευή του.', en: 'Part of its glory is still preserved today and the visitor can see from the precinct and the cells to the rooms and the main temple. Its name is mainly due to the red earth used as mortar for its construction.' }] },
  'Poros': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-poros.jpg', paragraphs: [{ el: 'Προέρχεται από τη λέξη Πόρος = οπή = τρύπα. Το βουνό συγκεκριμένα «ΚΑΜΠΗ» πάνω στο οποίο είναι χτισμένο το χωριό έχει τρύπες όπου κυλάει τρεχούμενο νερό. Από τα υπόγεια νερά του χωριού έχει υποχωρήσει το άνω μέρος του χωριού κι έχει βουλιάξει μέσα στη γη παρασύροντας και τα σπίτια μαζί.', en: 'It comes from the word Resource = hole = hole. The mountain in particular «KAMPI» on which the village is built has holes where running water flows. The upper part of the village has retreated from the underground water and has sunk into the earth, dragging the houses along with it.' }, { el: 'ΙΣΤΟΡΙΚΑ ΣΤΟΙΧΕΙΑ', en: 'HISTORICAL DATA' }, { el: 'Σήμα κατατεθέν του χωριού αποτελεί ο πύργος του 6 ου αιώνα π.Χ. του οποίου τα ερείπια σώζονται ακόμη στη θέση Πυργί. Ο πύργος είχε κτιστεί από τους Κορινθίους όταν κατέλαβαν το νησί. Είχε ύψος 12 μ. και σύμφωνα με τις νεότερες εκδοχές αποτελούσε ένα είδος «φρυκτωρίας». Δηλαδή μετάδοσης οπτικών μηνυμάτων ώστε να ενημερώνετε η μία άκρη του νησιού με την άλλη στην περίπτωση – κυρίως- εισβολέων.', en: 'A trademark of the village is the tower of 6 th century BC, the ruins of which are still preserved at Pyrgi. The tower was built by the Corinthians when they conquered the island. It was 12 m high and according to the latest versions it was a kind of «fryktoria». That is to say, the transmission of visual messages in order to inform one end of the island with the other in case of - mainly - invaders.' }, { el: 'ΛΑΟΓΡΑΦΙΚΑ ΣΤΟΙΧΕΙΑ', en: 'FOLKLORE DATA' }, { el: 'Ένα από τα πλουσιότερα σε λαογραφικό πλούτο και παράδοση χωριά της Λευκάδας.', en: 'One of the richest villages of Lefkada in terms of folklore and tradition.' }, { el: 'Ονομαστό από την οικογένεια των Καταποδαίων που υπήρξαν εξαιρετικοί μαχαιροποιοί αλλά και οπλοποιοί. Η συντεχνία των μαχαιροποιών ξεκίνησε το 1684 που κατέλαβαν οι Ενετοί το νησί. Χώρισαν τα διάφορα επαγγέλματα σε συντεχνίες ώστε να υπάρχει εξειδίκευση εργασίας και οι Ενετοί ως έμποροι που ήτων να πουλάνε τη παραγωγή. Η τέχνη συνεχίστηκε μέχρι το 1950 περίπου. Τώρα μένει η φήμη αλλά και οι δημιουργίες σε μαχαίρια που αποτελούν πλέον μουσειακά αντικείμενα.', en: 'Named after the family of the Katapodaians who were excellent knife makers and gunsmiths. The knife makers\' guild started in 1684 when the Venetians occupied the island. They divided the various trades into guilds so that there was specialization of work and the Venetians as merchants who were to sell the production. The craft continued until about 1950. Now what remains is the fame and the creations on knives that are now museum pieces.' }, { el: 'Γνωστός ο Πόρος για την πνευματική δημιουργία τόσο σε επιστήμονες όσο και σε ποιητές αλλά και παραμυθάδες, ξεχωρίζει και για τους επικήδειους που διαβάζονται σε κάθε κηδεία και κάθε περίπτωση. Έθιμα τουλάχιστον δύο αιώνων που και σήμερα ακόμη βρίσκεται σε εξέλιξη τονίζοντας το ψηλό πνευματικό αίσθημα των κατοίκων.', en: 'Poros is known for the spiritual creation of scientists, poets and storytellers alike, but it is also known for the eulogies that are read at every funeral and every occasion. A custom of at least two centuries that is still going on today, emphasizing the high spiritual feeling of the inhabitants.' }, { el: 'Στο χώρο το λατρευτικό υπάρχούν αξιόλογες εκκλησίες του 18 ου αιώνα και επίσης υπάρχουν κι αξιόλογα κτίρια παλιών γαιοκτημόνων του χωριού όπως του Κάπαλου, του Βερετή και του Κονιδάρη με αξιόλογα οικοδομικά στοιχεία.', en: 'In the place of worship there are remarkable churches of the 18th century. th century and there are also remarkable buildings of old landowners of the village such as Kapalos, Vereti and Konidaris with remarkable architectural elements.' }] },
  'Fterno': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-fterno.jpg', paragraphs: [{ el: 'ΙΣΤΟΡΙΚΑ ΣΤΟΙΧΕΙΑ', en: 'HISTORICAL DATA' }, { el: 'Η ονομασία του χωριού μάς ανάγει σε αρχαιοελληνικές καταβολές όμως η νεότερη εγκατοίκηση των κατοίκων μας οδηγεί σε άλλα ιστορικά συμπεράσματα.', en: 'The name of the village takes us back to ancient Greek origins but the more recent settlement of the inhabitants leads us to other historical conclusions.' }, { el: 'Το χωριό κατοικείται τουλάχιστον από τον 16 ο αιώνα αλλά μόλις ήρθαν οι Ενετοί το πύκνωσαν πληθυσμιακά. Συγκεκριμένα το επίθετο Αρματάς υποδηλώνει μισθοφόρους του Ενετικού στρατού που πολέμησαν κατά των Τούρκων και σε αντάλλαγμα πήραν εκτάσεις γης δικές τους καθώς και χρήματα που είχαν γραμμένα τη λέξη «ARMATA», εξού και το επίθετο που πήραν Αρματαίοι.', en: 'The village has been inhabited at least since 16 ο century but once the Venetians arrived they increased its population. Specifically, the adjective Armatas indicates mercenaries of the Venetian army who fought against the Turks and in return they got land of their own as well as money with the word «ARMATA» written on it, hence the adjective that they took Armataioi.' }, { el: 'Επίσης στα χρόνια των Ενετών εγκαταστάθηκαν και οι Σκλαβενιταίοι. Η καταγωγή αυτών είναι από τα Σκλάβαινα της Αιτ/νίας τα οποία τα έκαψαν οι Τούρκοι το 1690 και οι κάτοικοι που γλίτωσαν ήρθαν στον Πόρο και Φτερνό και στη συνέχεια στο Κατωχώρι όπου από τον τόπο καταγωγής τους βγήκε και το καιούργιο επίθετο.', en: 'Also during the years of the Venetians, the Slavenites settled in the area. Their origin is from Sklavina in Etnania, which were burned by the Turks in 1690 and the inhabitants who survived came to Poros and Fterno and then to Katochori, where their place of origin gave them their surname.' }, { el: 'ΛΑΟΓΡΑΦΙΚΑ ΣΤΟΙΧΕΙΑ', en: 'FOLKLORE DATA' }, { el: 'Η λαογραφία του χωριού είναι συνδεδεμένη με τον ποιμενικό τρόπο ζωής που όλους αυτούς τους αιώνες ακολουθεί.', en: 'The folklore of the village is linked to the pastoral way of life that has been followed for all these centuries.' }, { el: 'Η ζωοκλοπή αποτελούσε ανέκαθεν αναγκαίο κακό μιας και είχε ανδραγαθοποιηθεί στο μέγιστο βαθμό.', en: 'Animal theft has always been a necessary evil since it had been androgenized to the maximum extent.' }, { el: 'Στις μέρες μας έχει αλλάξει η όψη του χωριού με πολλούς δρόμους, πολλά καινούργια σπίτια και πολλούς ξένους που έχουν εγκατασταθεί εκεί. Το καλοκαίρι αποτελεί έναν αξιόλογο τουριστικό προορισμό τόσο για φαγητό όσο και διαμονή.', en: 'Nowadays the village has changed its appearance with many streets, many new houses and many foreigners who have settled there. In the summer it is a remarkable tourist destination for both food and accommodation.' }] },
  'Charadiatika': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-charadiatika.jpg', paragraphs: [{ el: 'Χρειάστηκε να ενωθούν τα Επτάνησα με την Ελλάδα για να αρχίσουν σιγά – σιγά οι απόκληροι των κατακτητών να φεύγουν από τα ορεινά μέρη που τους είχε καταδικάσει η αυθαιρεσία τους και ο φόβος από την λεηλασία των πειρατών να κατέβουν προς τα πιο πεδινά όπου έβρισκαν πιο γόνιμο έδαφος για να αναπτυχθούν οικονομικά και να συντηρήσουν οικογένειες.', en: 'It took the union of the Ionian Islands with Greece for the outcasts of the conquerors to slowly begin to leave the mountainous areas where their arbitrariness and fear of pirate plunder had condemned them to descend to the lower plains where they found more fertile ground to develop economically and support families.' }, { el: 'Έτσι έγινε και με τα Χαραδιάτικα . Ένα καινούργιο σχετικά χωριό, ιστορίας 2 -3 αιώνων που όμως έχει να επιδείξει κάποια αξιόλογα πέτρινα σπίτια, εκκλησίες καλντερίμια αρκετά όμορφα.', en: 'So it was with the Features . A relatively new village, with a history of 2 -3 centuries, but with some remarkable stone houses, churches, cobbled streets, quite beautiful.' }, { el: 'Τα τρεχούμενα νερά που έρχονται από το Άλατρο έχουν κάνει πολύ γόνιμο το έδαφος του χωριού και προχωρώντας μέσα στο φαράγγι συναντάει κανείς ακόμη τους παλιούς νερόμυλους αλλά και το φυσικό μεγαλείο που συνδυάζει το τρίπτυχο δέντρο, πέτρα και νερό.', en: 'The running waters that come from the Alatro have made the soil of the village very fertile and as one proceeds through the gorge one can still find the old watermills and the natural splendour that combines the triptych of tree, stone and water.' }] },
  'Egklouvi': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-egkloyvi.jpg', paragraphs: [{ el: 'Τέσσερα χιλιόμετρα μετά την Καρυά, σε υψόμετρο 730 μέτρων περίπου χτισμένη πάνω σε μικρούς λόφους, βρίσκεται η Εγκλουβή . Το ορεινότερο χωριό του νησιού. Στη σκιά του ανενεργού πλέον αμερικανικού ραντάρ, που κυριαρχεί στο υψηλότερο σημείο του χωριού, η Εγκλουβή αποκαλύπτεται: πέτρινα σπίτια με τοξωτές αυλόπορτες, κοσμήματα λαϊκής τέχνης, που ξυπνούν όμορφες μνήμες και στιγμές, μας κάνουν να αναπολούμε ρομαντικές εποχές συνδυάζοντας το χθες με το σήμερα, το σήμερα με το αύριο…, λιθόστρωτα δρομάκια, η πλατεία με τα πλατάνια και τις μουριές, οι γυναίκες με την παραδοσιακή λευκαδίτικη φορεσιά, οι χαμογελαστοί υπερήφανοι και συνάμα φιλόξενοι Εγκλουβησάνοι.', en: 'Four kilometers after Karya, at an altitude of about 730 meters built on small hills, is the Enclave . The most mountainous village of the island. In the shadow of the now defunct American radar, which dominates the highest point of the village, Egluvi is revealed: Stone houses with arched courtyard doors, jewels of folk art, which evoke beautiful memories and moments, make us reminisce about romantic times, combining yesterday with today, today with tomorrow..., cobbled streets, the square with plane trees and mulberry trees, women in traditional Lefkadian costume, the smiling proud and yet hospitable Egluvians.' }, { el: 'Κύρια ασχολία των κατοίκων η καλλιέργεια της πασίγνωστης φακής Εγκλουβής που δίκαια θεωρείται η καλύτερη και η νοστιμότερη στην Ελλάδα καθώς και η αμπελοκαλλιέργεια. Λίγο πιο πάνω από το χωριό και σε υψόμετρο 900 μέτρων ο επισκέπτης θα συναντήσει το εκκλησάκι του Αγίου Δονάτου που γιορτάζει στις 7 Αυγούστου. Την προηγούμενη μέρα γίνεται πανηγύρι στην περιοχή και οι Εγκλουβησάνες νοικοκυρές μαγειρεύουν με τον παραδοσιακό τρόπο φακές σε μεγάλα τσουκάλια και κερνούν τους επισκέπτες μαζί με ελιές, παστές σαρδέλες και κρασί.', en: 'The main occupation of the inhabitants is the cultivation of the well-known lentil Engluvius which is rightly considered the best and the tastiest in Greece, as well as the viticulture. A little further up from the village and at an altitude of 900 meters the visitor will find the chapel of Agios Donatos, which celebrates on August 7. On the day before, there is a festival in the area and the Egluvisane housewives cook lentils in the traditional way in large pots and treat the visitors with olives, salted sardines and wine.' }, { el: 'Απέναντι από το εκκλησάκι υπάρχει μια σειρά από πηγάδια με νερό “κρούσταλλο” και στη γύρω περιοχή αλώνια, ανεμόμυλοι, ο οικισμός των βόλτων αποτελούν μνημεία ενός ανυπέρβλητου πολιτισμού που δεν μπορεί να αφήσει ασυγκίνητο κανένα επισκέπτη. Οι Βόλτοι βρίσκονται αποκλειστικά και μόνο σε αυτόν τον τόπο και την κατασκευή τους επέβαλαν οι ειδικές συνθήκες καλλιέργειας της περιοχής. Μέσα σε κάθε βόλτο υπήρχε ένα μικρό νοικοκυριό για την εξυπηρέτηση των καλλιεργητών που έμεναν εκεί όλο το καλοκαίρι. Αμέτρητοι βόλτοι, (μικροί θολωτοί πέτρινοι οικίσκοι σε σχήμα φούρνου), απόδειξη ότι η περιοχή του Αγίου Δονάτου αποτελούσε κατά το μακρινό παρελθόν έναν πολυπληθή καλοκαιρινό οικισμό γεμάτο ζωή. Μετά το απαραίτητο προσκύνημα σε τούτο το πολύμορφο τοπίο με την αρχέγονη γοητεία, πάνω από το πλάτωμα του Αγίου Δονάτου σε μια από τις υψηλότερες κορυφές, ο επισκέπτης συναντά το ξωκλήσι του “αφ’ υψηλού” εποπτεύοντος φρουρού, Προφήτη Ηλία. Ερευνητές υποστηρίζουν ότι οι βόλτοι είναι της ομηρικής εποχής. Ο Κ. Δούκας αναφέρει χαρακτηριστικά “ότι τους χρησιμοποιούσε ο Όμηρος- Οδυσσέας”.', en: 'Opposite the chapel there is a series of wells with water “krustallo” and in the surrounding area threshing floors, windmills, the settlement of the volta are monuments of an unsurpassed culture that can not leave any visitor unmoved. The Volti are located exclusively in this place and their construction was imposed by the special cultivation conditions of the area. Inside each volta there was a small household to serve the farmers who lived there all summer. The countless voltae (small domed stone houses in the shape of an oven) are proof that the area of Agios Donatos was in the distant past a bustling summer settlement full of life. After the necessary pilgrimage to this varied landscape with its primeval charm, above the plateau of Agios Donatos on one of the highest peaks, the visitor comes across the chapel of the “high’ guardian, the Prophet Elias. Researchers claim that the walks are of Homeric times. K. Doukas says that ”Homer - Odysseus used them“.' }] },
  'Karya': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-karya.jpg', paragraphs: [{ el: 'Η Καρυά το ορεινό κεφαλοχώρι της Λευκάδας, απέχει 14 χλμ. από την πόλη της Λευκάδας, περίπου 20 λεπτά οδήγησης με το αυτοκίνητο. Είναι κτισμένη στις καταπράσινες πλαγιές του βουνού σε υψόμετρο 500 μέτρων, ενώ φημίζεται για το άριστο κλίμα της και το απαράμιλλης ομορφιάς φυσικό περιβάλλον της.', en: 'Η Karya the mountainous village of Lefkada, is 14 km from the town of Lefkada, about 20 minutes\' drive. It is built on the green slopes of the mountain at an altitude of 500 meters, while it is famous for its excellent climate and its natural environment of unparalleled beauty.' }, { el: 'Ο πληθυσμός της ανέρχεται περίπου στους 1.000 κατοίκους ενώ τους καλοκαιρινούς μήνες παρουσιάζει σημαντική αύξηση λόγω και της μεγάλης προσέλευσης τουριστών. Ξεκινώντας ο επισκέπτης την περιπλάνησή του από το δρόμο της κεντρικής αγοράς της Καρυάς θα συναντήσει την πετρόκτιστη βρύση με τα άφθονα τρεχούμενα νερά.Δίπλα της βρίσκεται η περίφημη ‘πλατεία της Καρυάς’ με τα αιωνόβια πλατάνια. Εκεί ο επισκέπτης μπορεί να απολαύσει φαγητό ή ποτό που προσφέρουν τα παραδοσιακά καφενεία και οι ταβέρνες. Αμέτρητα πλακόστρωτα δρομάκια που απλώνονται σε όλο τον οικισμό, παλιά αλλά και ανακαινισμένα πέτρινα σπίτια, παραδοσιακά κτισμένα, αυλές με πεζούλια, διάσπαρτα ιστορικά εκκλησάκια, ανεμόμυλοι, ξερολιθιές.', en: 'The population is about 1.000 inhabitants and during the summer months it shows a significant increase due to the large number of tourists. Starting his walk from the street of the central market of Karya, the visitor will meet the stone fountain with abundant running water.Next to it is the famous ‘square of Karya’ with the century-old plane trees. There the visitor can enjoy a meal or a drink offered by the traditional cafes and taverns. Countless cobbled streets spreading throughout the settlement, old and renovated stone houses, traditionally built, courtyards with terraces, scattered historical churches, windmills, dry stone walls.' }, { el: 'Στο κεντρικότερο σημείο του χωριού βρίσκεται η εκκλησία του Αγίου Σπυρίδωνος, με το επιβλητικό της καμπαναριό, η οποία κτίστηκε στα τέλη του 19 ου αιώνα. Στους πρόποδες της Καρυάς, στο λιβάδι, βρίσκεται το Μοναστήρι του Άι- Γιάννη του Προδρόμου που χτίστηκε το 1605 μ.Χ. Σήμερα στο μοναστήρι ο επισκέπτης μπορεί να θαυμάσει τις λιγοστές πια, αλλά εξαιρετικές τοιχογραφίες, το ξυλόγλυπτο τέμπλο καθώς και τα πέτρινα κελιά που πλαισιώνουν τον εξωτερικό χώρο της μονής. Η ιστορία του μοναστηριού είναι πλούσια, ενώ η συμβολή του στην οικονομική και πνευματική ζωή του τόπου αξιοσημείωτη.', en: 'At the central point of the village is the church of Agios Spyridonos, with its imposing bell tower, which was built at the end of the 19th century. th century. At the foot of Karya, in the meadow, is the Monastery of St. John the Baptist, built in 1605 AD. Today, visitors to the monastery can admire the few, but excellent frescoes, the carved wooden temple and the stone cells that surround the exterior of the monastery. The history of the monastery is rich, while its contribution to the economic and spiritual life of the area is remarkable.' }, { el: 'Στη νότια πλευρά του χωριού, στο λιβάδι της Καρυάς συναντά κανείς εκτάσεις με καλλιέργειες τοπικών προϊόντων, όπως είναι τα λαθούρια ή λαθύρια, τα ρεβύθια, τα μπιζέλια, η ελιά και τα αμπέλια.', en: 'On the south side of the village, in the meadow of Karya, one finds areas with cultivations of local products, such as lathouria, chickpeas, peas, olives and vines.' }, { el: 'Η Καρυά, ένα χωριό με πλούσια πολιτιστική παράδοση, έχει διατηρήσει πολλά από τα πατροπαράδοτα έθιμα του τόπου, με αποκορύφωμα την τριήμερη εκδήλωση της «Αναπαράστασης του Χωριάτικου γάμου», η οποία πραγματοποιείται σε ετήσια βάση από το 1979 και θεωρείται μια από τις σπουδαιότερες πολιτιστικές εκδηλώσεις της Λευκάδας.', en: 'Karya, a village with a rich cultural tradition, has preserved many of the traditional customs of the place, culminating in the three-day event of the «Representation of the Village Wedding», which has been held annually since 1979 and is considered one of the most important cultural events of Lefkada.' }, { el: 'Mια επίσκεψη στο ιδιωτικό Λαογραφικό Μουσείο της Καρυάς με τα παραδοσιακά εκθέματα, θα φέρει τον επισκέπτη κοντά στον τρόπο ζωής των κατοίκων του χθες, στην καθημερινότητα του απλού Λευκαδίτη.', en: 'A visit to the private Folklore Museum of Karya with its traditional exhibits will bring the visitor close to the way of life of the inhabitants of yesterday, to the everyday life of the ordinary Lefkadite.' }] },
  'Pigadisanoi': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-pigadisanoi.jpg', paragraphs: [{ el: 'Οι Πηγαδησάνοι απέχει ένα χιλιόμετρο από την έδρα της Δημοτικής Ενότητας Καρυάς και 12 χιλιόμετρα από την πρωτεύουσα Λευκάδα του ομωνύμου νησιού μας. Το χωριό είναι προσήλιο και χτισμένο, σχεδόν σκαρφαλωμένο σε καταπράσινη πλαγιά του βουνού, μέσα στις ελιές, και σε ένα κλασικό πράσινο διαφόρων αποχρώσεων, επτανησιακό περιβάλλον.', en: 'The Wells is one kilometer from the headquarters of the Municipal Unit of Karya and 12 kilometers from the capital Lefkada of our island of the same name. The village is built on a green mountain slope, almost perched on a green mountainside, surrounded by olive trees, and in a classic green, variously coloured, Ionian environment.' }, { el: 'Ο κεντρικός οδικός άξονας αποτελεί τη ραχοκοκαλιά του χωριού και εκατέρωθεν απλώνονται οι γραφικές γειτονιές του. Ο επισκέπτης θα καθηλωθεί από την υπέροχη θέα που προσφέρει η ίδια η θέση του χωριού που λειτουργεί σαν μπαλκόνι.', en: 'The main road is the backbone of the village and on either side of it are the picturesque neighbourhoods. The visitor will be captivated by the wonderful view offered by the very location of the village, which acts as a balcony.' }, { el: 'Στα πόδια του χωριού εκτείνεται το Λιβάδι της Καρυάς στο οποίο παρελαύνουν όλα τα χρώματα ανάλογα με την εποχή. Πέρα στην άκρη του Λιβαδιού βρίσκεται το ανακαινισμένο μοναστήρι του Αγίου Ιωάννη του Προδρόμου, ένας πνευματικός φάρος της περιοχής αλλά και ολόκληρου του νησιού για πολλούς αιώνες.', en: 'At the foot of the village stretches the Livadi of Karya where all the colours parade depending on the season. Beyond the edge of the Livadi is the renovated monastery of Agios Ioannis Prodromos, a spiritual beacon of the region and the entire island for many centuries.' }, { el: 'Στο κέντρο του χωριού ο επισκέπτης θα απολαύσει τον καφέ αλλά και τους μεζέδες με ντόπιο καλό κρασί και τσίπουρο. Στην πλατεία δίπλα στη εκκλησία του Αγίου Νικολάου το καλοκαίρι θα παρουσιαστεί αξιόλογη πολιτιστική δημιουργία. Η καθιερωμένη Γιορτή Κρασιού προσελκύει πλήθος κόσμου.', en: 'In the center of the village the visitor will enjoy coffee and appetizers with local good wine and tsipouro. In the square next to the church of Agios Nikolaos in the summer, a remarkable cultural creation will be presented. The well-established Wine Festival attracts a large number of people.' }, { el: 'Ανηφορίζοντας θα φτάσεις στην εκκλησία των Αγίων Αναργύρων με αξιόλογο τέμπλο και υπέροχη θέα. Συνεχίζοντας και έξω πλέον από το χωρίο θα συναντήσεις το ξωκλήσι της Θεοτόκου, εκεί που η θέα γίνεται πλέον πανοραμική.', en: 'Going uphill you will reach the church of Agioi Anargyroi with a remarkable iconostasis and a wonderful view. Continuing on and out of the village you will meet the chapel of Theotokos, where the view becomes panoramic.' }, { el: 'Κατηφορίζοντας θα περάσεις μέσα από τις αιωνόβιες ελιές και τις γειτονιές του κάτω χωριού και θα φτάσεις στους Μάρκους. Εδώ ο συνδυασμός του πέτρινου παλιού γεφυριού, των πηγαίων νερών , του παλιού νερόμυλου και της βρύσης , δημιουργεί ένα ιδιαίτερης ομορφιάς τοπίο.', en: 'Going downhill you will pass through the centuries-old olive trees and the neighbourhoods of the lower village and you will reach Marcus. Here the combination of the old stone bridge, the wells, the waterfalls and the old bridge water , of old water mill and the tap , creates a landscape of particular beauty.' }, { el: 'Από τούτα τα χώματα κατάγονται ο αγωνιστής-σύμβολο της εθνικής αντίστασης Απόστολος Σάντας και η τραγουδίστρια της όπερας Αγνή Μπάλτσα. Ο τόπος αυτός σε καλεί να ζήσεις ανθρώπινα σε ρυθμούς ήρεμους και να ανακαλύψεις τη φιλοξενία των κατοίκων του.', en: 'The fighter-symbol of the national resistance Apostolos Sandas and the opera singer Agni Baltsa come from these lands. This place invites you to live humanly at a calm pace and discover the hospitality of its inhabitants.' }] },
  'Lazarata': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Asprogerakata': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Drymonas': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Exanthia': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Kavallos': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Pinakochori': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Spanochori': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-sfakiotes.jpg', paragraphs: [{ el: 'Η θέα που μπορεί κανείς να απολαύσει από όλα τα χωριά των Σφακιωτών, είτε προς την πόλη της Λευκάδας, είτε προς τη θάλασσα ανατολικά και δυτικά, είναι μοναδική. Επίσης οι λόφοι γύρω από τα χωριά συνθέτουν ένα τοπίο από φυσικό και δομημένο περιβάλλον, που σίγουρα θα συγκινήσει τον επισκέπτη. Παραδοσιακά πέτρινα σπίτια, εκκλησίες, καμπαναριά, ανεμόμυλοι, νερόμυλοι, πηγές, πηγάδια, αποτελούν την ταυτότητα της περιοχής. Εδώ βρίσκεται ένα πλήθος μονοπατιών και περιπατητικών διαδρομών που αξίζει να απολαύσετε.', en: 'The view that one can enjoy from all the villages of Sfakiotes, either towards the town of Lefkada or towards the sea to the east and west, is unique. Also the hills around the villages compose a landscape of natural and built environment, which will surely move the visitor. Traditional stone houses, churches, bell towers, windmills, watermills, springs, wells, are the identity of the area. Here is a multitude of paths and hiking trails that are worth enjoying.' }, { el: 'Ενδεικτικά αναφέρουμε: Σπανοχώρι (θέση Καταποτήρας) – ξωκλήσι Προφήτη Ηλία. Ξωκλήσι Προφήτη Ηλία – Άγιος Στέφανος (εκκλησία μέσα σε σπηλιά, με μοναδική θέα προς την ανατολική πλευρά του νησιού ). Μονοπάτι Δασυλλίου «Θρομπερό», στα Λαζαράτα. Από τον Κάβαλο, το μονοπάτι Ράχη – Καλή, Καλή – Πρεμεντινός, Πρεμεντινός – Άγιος Σπυρίδωνας, στα Λαζαράτα. Λεμονή – Σπηλιά – Κιόνια – Λαριό – Καλοήρα – Φάσου – Ξοβελόνι', en: 'For example: Spanochori (location Katapotiras) - chapel of Prophet Elias. Chapel of Prophet Elias - Agios Stefanos (church in a cave, with a unique view to the east side of the island). Dasillia Trail «Throbero», in Lazarata. From Kavalos, the path Rachi - Kali, Kali - Prementinos, Prementinos - Agios Spyridon, to Lazarata. Lemomi - Spilia - Kionia - Lario - Kaloira - Fasu - Xoveloni' }, { el: 'Επίσης στο φαράγγι της Μέλισσας και σε όλη την ευρύτερη περιοχή, λίγο έξω και βόρεια από το χωριό Κάβαλος, θα βρείτε ένα δίκτυο μονοπατιών και περιπατητικών διαδρομών. Εδώ, στην περιοχή της Μέλισσας, σώζονται ερείπια μικρών οικισμών, παλιοί νερόμυλοι, πολλά πέτρινα γεφύρια, πηγάδια και πηγές, όπως αυτή της «Σπηλιάς» απ’ όπου αναβλύζουν ακόμα κρυστάλλινα νερά και ο επισκέπτης μπορεί να ξεδιψάσει, να ξεκουραστεί και να γαληνέψει.', en: 'Also in the Melissa Gorge and throughout the wider area, just outside and north of the village of Kavalos, you will find a network of paths and hiking trails. Here, in the area of Melissa, there are ruins of small settlements, old watermills, many stone bridges, wells and springs, such as that of the «Cave» from which crystal clear waters still gush forth and the visitor can quench his thirst, rest and relax.' }, { el: 'Θα φτάσετε εκεί, φεύγοντας απ’ την πόλη της Λευκάδας, αφού πάρετε τον επαρχιακό προς τον Δήμο Σφακιωτών. Διανύοντας 6 χιλιόμετρα θα φτάσετε εκεί που ο Δήμος Σφακιωτών κατασκεύασε το Μνημείο για την εξέγερση των χωρικών κατά της Αγγλικής Προστασίας τον Οκτώβρη του 1819 τότε θα στρίψετε δεξιά στον ασφαλτοστρωμένο αγροτικό δρόμο και θα διασχίσετε μια διαδρομή μέσα σε θαυμάσιους ελαιώνες. Μετά από 3 χιλιόμετρα θα στρίψετε δεξιά ακολουθώντας τον Αγροτικό χωμάτινο δρόμο μια υπέροχη διαδρομή 2 χιλιομέτρων που θα μας οδηγήσει στην είσοδο, του φαραγγιού της Μέλισσας. Εκεί βρίσκεται ένα πέτρινο γεφύρι και η «Σπηλιά» η οποία είναι «σκαμμένη» φυσικά σε ένα τεράστιο βράχο. Εκεί θα δούμε και την ονομαστή ομώνυμο πηγή που αναβλύζουν κρυστάλλινα νερά και μπορείτε να ξεδιψάσετε και να ξεκουραστείτε.', en: 'You will get there, leaving the town of Lefkada, after taking the provincial road to the municipality of Sfakiotes. After 6 km you will reach the place where the Municipality of Sfakiotes built the Monument to the revolt of the peasants against the British Protection in October 1819, then you will turn right on the asphalted rural road and cross a path through wonderful olive groves. After 3km you will turn right following the rural dirt road a lovely 2km route that will take you to the entrance, the entrance to the Melissa Gorge. There is a stone bridge and the «Cave» which is naturally dug into a huge rock. There you will also see the famous homonymous spring where crystal clear waters gush out and you can quench your thirst and rest.' }, { el: 'Την περιοχή διασχίζει ορμητικός χείμαρρος που τροφοδοτεί άλλους 6 νερόμυλους της περιοχής απ΄ τους 64 που ήταν στο νησί σε λειτουργία το 1814. Όλοι οι νερόμυλοι είναι συνέχεια ο ένας μετά τον άλλον στην ίδια λαγκαδιά και σύμφωνα με μαρτυρίες δούλευαν τον Χειμώνα και την Άνοιξη χρησιμοποιώντας τα επιφανειακά νερά των χειμάρρων.', en: 'The area is crossed by a rushing torrent that feeds 6 other watermills of the 64 that were in operation on the island in 1814. All the watermills are located one after the other in the same valley and according to testimonies they worked in winter and spring using the surface waters of the torrents.' }, { el: 'Οι νερόμυλοι είναι μονοκάμαρα μικρόσπιτα χτίσματα με μάντρες. Για ανοίγματα έχουν μια πόρτα και ένα, σπάνια δύο παράθυρα. Η στέγη των νερόμυλων ήταν σκεπασμένη πάντα με κεραμίδια και ήταν επικλινής μονόρριχη . Συνεχίζοντας τον χωμάτινο δρόμο των 2 χιλιομέτρων απ’ την είσοδο του φαραγγιού φτάνουμε στο μεγάλο πλάτωμα με τους νερόμυλούς του «Κοσπέτου». Απ’ το σημείο αυτό και μετά υπάρχουν 2 άριστα διαμορφωμένα μονοπάτια με προστατευτικά ξύλινα κιγκλιδώματα. Το ένα μονοπάτι αριστερά προς την «Απεταστή» μια τοποθεσία με πολλά νερά και το άλλο μονοπάτι δεξιά περνώντας το πέτρινο γεφύρια προς το «Καλό λαγκάδι. Μια μαγευτική διαδρομή με ξύλινα γεφύρια και νερόμυλους. Μάλιστα στον τελευταίο στην σειρά νερόμυλο γίνονταν επεξεργασία θειαφιού.', en: 'The watermills are one-roomed small houses built with paddocks. For openings they have a door and one, rarely two windows. The roof of the watermills was always covered with tiles and was sloping and single-pitched. Continuing along the 2 km dirt road from the entrance of the gorge, we reach the large plateau with the watermills of ’Kospetos«. From this point onwards there are 2 well-maintained paths with protective wooden railings. One trail to the left towards »Apetasti’ a site with lots of water and the other trail to the right passing the stone bridges towards «Kalo Lagadi». A magnificent route with wooden bridges and water mills. In fact, the last watermill in the row was used for processing of theiafiu.' }, { el: 'Στο φαράγγι συναντούμε κυπαρίσσια, δάφνες, πλατάνια, δρυς, πουρνάρια, σκλήθρα, βάτα, αγριοτριανταφυλλιές, αγριοκουτσουπιές, μυρτιές, χρυσόξυλα, σχίνους, κοκορεβιθιές, ιτιές, αρίκια, κουμαριές, λυγαριές, παλιούρια, σπάρτα,ασπάλαθούς, ασφάκες, κρόκους κ.α. Απ’ το ζωικό βασίλειο συναντάμε τρυγόνια, ξεφτέρια,μπεκάτσες, κουνάβια, ασβούς, νυφίτσες, ακανθόχοιρους, φάσσες, πέρδικες, Μελισσοφαγούς, τσαλαπετεινούς, καρακάξες, συκοφάγους, οχιές, σαιτάρια κ.α.', en: 'In the gorge we can find cypresses, laurels, plane trees, oaks, holly, alder, alder, birch, wild roses, wild chickweed, myrtles, cherry trees, chrysanthemums, schistos, rowan trees, willows, willow trees, arikias, kumarias, wisteria, wicker, skunk crabs, asparagus, aspalaths, asphlakes, crocuses, etc. Of the animal kingdom, we find turtles, waders, snipe, skunks, badgers, weasels, weasels, porcupines, porcupines, pheasants, partridges, bee-eaters, chaffinches, jays, magpies, sycamores, vipers, skeeters, etc.' }, { el: 'Το είδος της διαδρομής είναι σχετικά εύκολο. Ξεκινάμε απ΄ την είσοδό του φαραγγιού με υψόμετρο 320 μ και καταλήγουμε στο τέλος του μονοπατιού στο Κακό λαγκάδι σε υψόμετρο 150μ. Το συνολικό μήκος του είναι περίπου 2 χιλιόμετρα για την διάσχιση του απαιτείται περίπου μία ώρα. Φρυάς : Τοποθεσία στο χωριό Ασπρογερακάτα όπου υπάρχουν τρία μεγάλα ιστορικά πηγάδια, από τα οποία υδρεύονταν ολοχρονίς όλα τα χωριά του Δήμου Σφακιωτών. Εκεί υπάρχουν επίσης και δύο αιωνόβια πλατανιά που φυτεύτηκαν στα 1845. Στην περιοχή υπάρχει και η πέτρινη εκκλησία της Αναλήψεως με το θαυμάσιο καμπαναριό. Ο Αριστοτέλης Βαλαωρίτης γράφει σε στίχο του ποιήματος: ΦΩΤΕΙΝΟΣ: «Με του Φρυά το κρύο νερό».', en: 'The type of route is relatively easy. We start from the entrance of the gorge at an altitude of 320 m and end up at the end of the path at Kako lagadi at an altitude of 150 m. The total length of the path is about 2 km and it takes about an hour to cross it. Fryas : Location in the village of Asprogerakata where there are three large historical wells, from which all the villages of the Municipality of Sfakiotes were watered all along. There are also two century-old plane trees planted there in 1845. In the area there is also the stone church of Ascension with its magnificent bell tower. Aristotle Valaoritis writes in a verse of the poem.' }, { el: 'Στο Φρυά, μεταξύ Καβάλου και Ασπρογερακάτων, βρίσκονται πηγάδια ιδιαίτερης τεχνοτροπίας από την περίοδο 1478-1684. Ένα από αυτά, το περίφημο ‘πηγάδι του Φρυά’ υδροδοτούσε όλα τα χωριά του Δήμου. Στο Φρυά υπάρχουν και τα δύο υπεραιωνόβια πλατάνια, που μαζί με το ‘πηγάδι του Φρυά’ – που ο περίβολος του ανακατασκευάστηκε πρόσφατα σύμφωνα με το πρωτότυπό του, συνθέτουν την χαρακτηριστική φυσιογνωμία της περιοχής.', en: 'In Frya, between Kavala and Asprogerakata, there are wells of special style from the period 1478-1684. One of them, the famous ‘well of Fryas’ supplied water to all the villages of the municipality. In Fryas there are two old-growth plane trees, which, together with the ‘well of Fryas’ - the enclosure of which was recently reconstructed according to its original, make up the characteristic physiognomy of the area.' }, { el: 'Πεζοπορικό μονοπάτι Σπανοχωρίου (θέση καταποτήρας) εως το ξωκλήσι του Προφήτη Ηλία και του Αγίου Στεφάνου : Ξεκινώντας απ’ την τοποθεσία Καταποτήρας Σπανοχωρίου μπορούμε να περπατήσουμε το ανηφορικό λιθόστρωτο μονοπάτι προς το ξωκλήσι του Προφήτη Ηλία και στην συνέχεια του Αγίου Στεφάνου. Η θεά προς την κοιλάδα και τα χωριά του Δήμου Σφακιωτών είναι μαγευτική. Η διαδρομή ξεκινάει από 440 υψόμετρο και καταλήγει 540. Είναι διάρκειας 35 περίπου λεπτών και στην κορυφή του θα συναντήσουμε το Πέτρινο Ξωκλήσι του Προφήτη Ηλία, που χτίστηκε επί τουρκοκρατίας (1479-1684). Είναι ευκαιρία να σταματήσουμε για να δροσιστούμε με το κρύο νερό απ’ το βαθύ πηγάδι που υπάρχει στην αυλή του και να αγναντέψουμε την Λευκάδα, την Πρέβεζα και όλο το Ιόνιο Πέλαγος. Στη συνέχεια κάνοντας με μικρή διαδρομή συναντάμε το Ξωκλήσι του Αγίου Στεφάνου που είναι χρισμένο μέσα σε μια Σπηλιά με μοναδική θέα προς την ανατολική πλευρά του νησιού.', en: 'Hiking trail of Spanochori (swallow site) to the chapel of Prophet Elias and Agios Stefanos : Starting from the location Katapotiras of Spanochori we can walk the uphill cobbled path to the chapel of Prophet Elias and then to Agios Stefanos. The view towards the valley and the villages of the Municipality of Sfakiotes is magnificent. The route starts at 440 altitude and ends at 540. It lasts about 35 minutes and at the top we will meet the Stone Chapel of Prophet Elias, built during the Turkish occupation (1479-1684). It is an opportunity to stop to cool off with the cold water from the deep well in its courtyard and to look out over Lefkada, Preveza and the whole Ionian Sea. Then taking a short route we come across the Chapel of Agios Stefanos which is anointed in a cave with a unique view to the eastern side of the island.' }, { el: 'Οι εκκλησίες της περιοχής είναι από τα πλέον αντιπροσωπευτικά δείγματα της τοπικής αρχιτεκτονικής φυσιογνωμίας: Στο Σπανοχώρι, ψηλά στον απέναντι λόφο, η παλιά μονή αφιερωμένη στον Προφήτη Ηλία. Όπως προκύπτει από παλιά έγγραφα, ο ναός παραχωρήθηκε ερειπωμένος από την ενετική κυβέρνηση στον ιερέα Μελέτιο Βονασιέρη, ο οποίος ξανάχτισε τη μονή. Αλλεπάλληλες πυρκαγιές κατάστρεψαν μεγάλο μέρος του μοναστηριού. Πρόσφατα επισκευάστηκε και είναι επισκέψιμη. Άλλο ένα αξιόλογο μνημείο του τόπου είναι το ξωκκλήσι του Παντοκράτορα που βρίσκεται 1 χλμ. βορειοανατολικά του χωριού Κάβαλος. Στην πόρτα του υπάρχουν ανώθυρα από αρχαίους ελληνικούς ναούς. Η καμπάνα του κρέμεται από την τεράστια βελανιδιά μπροστά στην αυλή του. Δίπλα στο εκκλησάκι υπάρχει ημιερειπωμένος ο «ανεμόμυλος του Κοσπέτου» και λίγο πιο κάτω τα τρία παλιά «πηγάδια του Στενόφρυα».', en: 'The churches of the area are among the most representative examples of the local architectural character: In Spanochori, high on the opposite hill, the old monastery dedicated to Prophet Elias. According to old documents, the ruined church was granted by the Venetian government to the priest Meletios Bonasieris, who rebuilt the monastery. Successive fires destroyed much of the monastery. It was recently repaired and is open to visitors. Another remarkable monument of the place is the chapel of Pantokrator which is located 1 km northeast of the village of Kavalos. On its door there are lintels from ancient Greek temples. Its bell hangs from the huge oak tree in front of its courtyard. Next to the chapel there is the semi-deserted «windmill of Kospetos» and a little further on the three old «wells of Stenofryas».' }, { el: 'Πολλά παραδοσιακά καμπαναριά στολίζουν τις εκκλησίες των Σφακιωτών, το καθένα με τα δικά του ιδιαίτερα χαρακτηριστικά. Από τα ωραιότερα είναι αυτά του Αγίου Διονυσίου και του Αγίου Σπυρίδωνα, στα Λαζαράτα, καθώς και του Αγίου Ιωάννη στα Ασπρογερακάτα, που έχουν χτιστεί πριν από 150 τουλάχιστον χρόνια.', en: 'Many traditional bell towers adorn the churches of Sfakiotes, each with its own special characteristics. Among the most beautiful are those of Agios Dionysios and Agios Spyridon, in Lazarata, and Agios Ioannis in Asprogerakata, built at least 150 years ago.' }, { el: 'Ο ναός του Αγίου Σπυρίδωνα χτίστηκε στα μέσα του 18ου αιώνα. Το τέμπλο του είναι σε ρυθμό μπαρόκ, σε άσπρο και χρυσαφί χρώμα με λεπτούς κίονες κορινθιακού ρυθμού.', en: 'The church of Agios Spyridon was built in the middle of the 18th century. Its iconostasis is in baroque style, in white and gold with thin columns of Corinthian style.' }, { el: 'Η εικόνα του Αρχαγγέλου Μιχαήλ στο θυρόφυλλο ανήκει πιθανότατα στον αγιογράφο Β.Σιδέρη (1894). Το καμπαναριό του, χτισμένο με μαλακή πέτρα σε τρεις ορόφους, είναι ψηλό και επιβλητικό. Ο ναός του Αγίου Νικολάου στον Κάβαλο, είναι από τους παλαιότερους της περιοχής.', en: 'The icon of Archangel Michael on the door leaf probably belongs to the hagiographer V. Sideris (1894). The bell tower, built with soft stone on three floors, is tall and imposing. The church of Agios Nikolaos in Kavalos is one of the oldest in the area.' }] },
  'Kalamos': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-kalamos.jpg', paragraphs: [{ el: 'Νησί του Ιονίου πελάγους, ΝΑ της Λευκάδας, μεταξύ των νησιών Μεγανησίου ΔΒΔ, Καστού ΝΝΑ και της ακτής της Ακαρνανίας ΒΒΑ.', en: 'Island in the Ionian Sea, SE of Lefkada, between the islands of Meganissi NWW, Kastos SE and the coast of Akarnania NE.' }, { el: 'Έχει σχήμα επίμηκες, επιφ. 25 τ.χμ., 7ο της Επτανήσου, 59ο της Χώρας. Ακραία σημεία τα ακρωτήρια Κεφάλι ΝΔ, Ασπρογιάλι ΒΑ και Τράχηλας ΒΔ Μήκος ΝΔ – ΒΑ 12 χμ. Μέγιστο ύψος 745 μ. (κορυφή Βουνί), σχεδόν στο κέντρο του.', en: 'It has an elongated shape, epiph. 25 sq.km., 7th of the Ionian Sea, 59th of Chora. Extreme points are the capes of Kefali SW, Asprogiali NE and Trachilas NW. Length SW - NE 12 km. Maximum height 745 m. (peak Vouni), almost in the centre.' }, { el: 'Διοικητικώς ανήκει στην επαρχία Λευκάδος του νομού Λευκάδος, έχει μία κοινότητα και 2 οικισμούς, τον Κάλαμο στα ΝΔ και την Επισκοπή στη βόρεια ακτή, και πληθυσμό (απογραφή 2001) 465 άτομα. Έδαφος ορεινό, με μια βουνοκορφή να διατρέχει όλο το μήκος του. Οι ακτές του βραχώδεις και αλίμενες στο μεγαλύτερο μέρος τους,', en: 'Administratively it belongs to the province of Lefkados, has one community and 2 settlements, Kalamos on the southwest and Episkopi on the north coast, and a population (2001 census) of 465 people. The terrain is mountainous, with a mountain peak running its entire length. The coastline is rocky and salted for the most part,' }, { el: 'Σχηματίζουν δύο σχετικώς μεγάλους όρμους: A. στο ΝΔ τμήμα τους, το Γερολιμιώνα B. στο ΝΑ τμήμα τους, το λιμάνι Πόρτο Λεόνε. Κοντά στο ΝΔ τμήμα του νησιού Βρίσκεται η βραχονησίδα Φορμίκουλα.', en: 'They form two relatively large bays: A. in their SW part, Gerolimiona B. in their south-eastern part, the port of Porto Leone. Near the southwestern part of the island is the islet of Formicula.' }] },
  'Kastos': { image: 'https://lefkada.gov.gr/wp-content/uploads/2021/10/dimos-leykadas-kastos.jpg', paragraphs: [{ el: 'Μικρό, καταπράσινο νησάκι με υπέροχες παραλίες που προσφέρει εξαιρετική ηρεμία στους επισκέπτες του.', en: 'A small, green island with beautiful beaches that offers great tranquility to its visitors.' }, { el: 'Ο Καστός , ή η Καστός είναι μικρή κατοικίσιμη νησίδα του Ιονίου Πελάγους απέναντι από τη δυτική ακτή της Αιτωλοακαρνανίας, του λιμένα Αστακού, και νότια του μεγαλύτερου νησιού Κάλαμος, που θεωρείται προσάρτημά του. Επί του νησιού υφίσταται ομώνυμο χωριό.', en: 'Ο Castes , or Kastos, is a small inhabited island in the Ionian Sea opposite the west coast of Aitoloakarnania, the port of Astakos, and south of the larger island of Kalamos, which is considered an appendage. There is a village of the same name on the island.' }, { el: 'Ο Καστός είναι η μκρότερη κατοικίσιμη νησίδα των Επτανήσων και προσαρτήθηκε στην Ελλάδα το 1864. Παλαιότερα αποτελούσε μέρος της επαρχίας Ιθάκης του νομού Λευκάδας με πληθυσμό το 1950, τους 285 κατοίκους στο οποίο υφίστατο δημοτικό σχολείο.', en: 'Kastos is the smallest inhabitable island of the Ionian Islands and was annexed to Greece in 1864. It used to be part of the Ithaca district of the prefecture of Lefkada with a population of 285 inhabitants in 1950, where there was a primary school.' }, { el: 'Κύρια προϊόντα της νήσου αυτής είναι σιτηρά, σταφύλια και ωραίο κρασί. Όπως και ο γειτονικός Κάλαμος, επικοινωνεί με την ακτή της Αιτωλοακαρνανίας με καΐκια, από και προς το απέναντι χωριό Μύτικα.', en: 'The main products of this island are cereals, grapes and fine wine. Like the neighbouring Kalamos, it is connected to the coast of Aitoloakarnania by boats, from and to the opposite village of Mytikas.' }] },
};
